// Preserve existing iPhone data while upgrading older storage formats.
(function migrateBudgetIQIphoneStorage() {
  const schemaKey = 'budgetiq-storage-schema-version';
  const monthlyPaymentsKey = 'budgetiq-member-payments-by-month';
  try {
    if (!localStorage.getItem(monthlyPaymentsKey)) {
      const legacyPayments = JSON.parse(localStorage.getItem('budgetiq-member-payments') || '{}');
      const selectedMonth = localStorage.getItem('budgetiq-selected-month') || 'July 2026';
      const isLegacyPaymentMap = legacyPayments
        && typeof legacyPayments === 'object'
        && !Array.isArray(legacyPayments)
        && Object.values(legacyPayments).every((value) => typeof value === 'boolean');
      localStorage.setItem(monthlyPaymentsKey, JSON.stringify({
        [selectedMonth]: isLegacyPaymentMap ? legacyPayments : {}
      }));
    }
    localStorage.setItem(schemaKey, '3');
  } catch (error) {
    // The UI will show a save error if iPhone storage is unavailable.
  }
})();

// =======================================================
// 1. UNIFIED GLOBAL TOAST & NOTIFICATION ENGINE
// =======================================================
let globalToastTimeout;

function showToast(message, iconName, colorClass) {
  clearTimeout(globalToastTimeout);

  // List of possible toast container IDs across all screens
  const toastIds = [
    'trackingToast',
    'customizerToast',
    'driverToast',
    'feedToast',
    'kitchenToast',
    'boardToast',
    'calendarToast',
    'profileToast',
    'rewardsToast',
    'planToast'
  ];

  let activeToastEl = null;
  for (const id of toastIds) {
    const el = document.getElementById(id);
    if (el) {
      activeToastEl = el;
      break;
    }
  }

  if (!activeToastEl) return;

  const msgLabel = activeToastEl.querySelector('#toastMessage') || activeToastEl.querySelector('#toastText');
  if (msgLabel) {
    msgLabel.innerText = message;
  }

  // Update classes smoothly
  activeToastEl.className = `fixed bottom-24 left-1/2 -translate-x-1/2 bg-zinc-950 border border-zinc-800 ${colorClass || 'text-[#C1FF72]'} text-[11px] font-extrabold px-5 py-3.5 rounded-full shadow-2xl flex items-center gap-2 whitespace-nowrap opacity-100 translate-y-0 transition-all duration-300 z-50`;

  const iconEl = activeToastEl.querySelector('.material-icons');
  if (iconEl) {
    iconEl.innerText = iconName || 'info';
  }

  globalToastTimeout = setTimeout(() => {
    activeToastEl.classList.add('opacity-0', 'pointer-events-none', 'translate-y-3');
    activeToastEl.classList.remove('opacity-100', 'translate-y-0');
  }, 2500);
}

// Map triggerToast to the same unified handler
function triggerToast(message, iconName, colorClass) {
  showToast(message, iconName, colorClass);
}


