const BUDGETIQ_EXPENSES_KEY = 'budgetiq-expenses';
const BUDGETIQ_EXPENSE_DRAFTS_KEY = 'budgetiq-expense-drafts-by-month';
const BUDGETIQ_EXPENSE_DEFAULT_BUYER_KEY = 'budgetiq-expense-default-buyer';
const EXPENSE_CATEGORY_CONFIG = {
  housing: { label: 'Housing', icon: 'home', gradient: 'from-amber-500 to-orange-500' },
  utilities: { label: 'Utilities', icon: 'bolt', gradient: 'from-indigo-500 to-purple-600' },
  groceries: { label: 'Groceries', icon: 'shopping_basket', gradient: 'from-emerald-500 to-teal-600' },
  transport: { label: 'Transport', icon: 'directions_car', gradient: 'from-sky-500 to-blue-600' },
  health: { label: 'Health', icon: 'medical_services', gradient: 'from-rose-500 to-red-600' },
  other: { label: 'Other', icon: 'receipt_long', gradient: 'from-zinc-500 to-zinc-700' }
};
let expenseEntries = [];
let expenseNote = '';
let expenseEditingId = null;
let expenseReceiptData = '';
let expenseReceiptName = '';
let expenseDefaultBuyerId = '';
let expenseEditorBuyerId = '';
let expensePendingBuyerId = '';
let expenseBuyerSelectionTarget = 'default';
let expenseDraftSaveTimeout = null;

function getBudgetIQExpenseDraftMonth() {
  try {
    return localStorage.getItem('budgetiq-selected-month') || 'July 2026';
  } catch (error) {
    return 'July 2026';
  }
}

function updateBudgetIQExpenseDraftStatus(message, isError = false) {
  const label = document.getElementById('expenseDraftStatus');
  if (!label) return;
  label.textContent = message;
  label.className = isError
    ? 'text-[9px] font-extrabold text-red-400'
    : 'text-[9px] font-extrabold text-[#C1FF72]';
}

function readBudgetIQExpenseDrafts() {
  try {
    const drafts = JSON.parse(localStorage.getItem(BUDGETIQ_EXPENSE_DRAFTS_KEY) || '{}');
    return drafts && typeof drafts === 'object' && !Array.isArray(drafts) ? drafts : {};
  } catch (error) {
    return {};
  }
}

function saveBudgetIQExpenseDraft() {
  if (!document.getElementById('subtotalVal')) return true;
  const noteInput = document.getElementById('expenseNoteInput');
  if (noteInput) expenseNote = noteInput.value.trim();
  const month = getBudgetIQExpenseDraftMonth();
  const drafts = readBudgetIQExpenseDrafts();
  const hasDraft = expenseEntries.length > 0 || Boolean(expenseNote);

  if (hasDraft) {
    drafts[month] = {
      version: 1,
      savedAt: new Date().toISOString(),
      entries: expenseEntries,
      note: expenseNote,
      defaultBuyerId: expenseDefaultBuyerId
    };
  } else {
    delete drafts[month];
  }

  try {
    if (expenseDefaultBuyerId) localStorage.setItem(BUDGETIQ_EXPENSE_DEFAULT_BUYER_KEY, expenseDefaultBuyerId);
    else localStorage.removeItem(BUDGETIQ_EXPENSE_DEFAULT_BUYER_KEY);
    localStorage.setItem(BUDGETIQ_EXPENSE_DRAFTS_KEY, JSON.stringify(drafts));
    updateBudgetIQExpenseDraftStatus(hasDraft ? 'Draft saved' : 'Auto-save ready');
    return true;
  } catch (error) {
    updateBudgetIQExpenseDraftStatus('Draft not saved', true);
    return false;
  }
}

function scheduleBudgetIQExpenseDraftSave() {
  clearTimeout(expenseDraftSaveTimeout);
  updateBudgetIQExpenseDraftStatus('Saving draft…');
  expenseDraftSaveTimeout = setTimeout(saveBudgetIQExpenseDraft, 350);
}

function restoreBudgetIQExpenseDraft() {
  const draft = readBudgetIQExpenseDrafts()[getBudgetIQExpenseDraftMonth()];
  try {
    expenseDefaultBuyerId = localStorage.getItem(BUDGETIQ_EXPENSE_DEFAULT_BUYER_KEY) || '';
  } catch (error) {
    expenseDefaultBuyerId = '';
  }
  if (!draft || typeof draft !== 'object') {
    updateBudgetIQExpenseDraftStatus('Auto-save ready');
    return false;
  }

  expenseEntries = Array.isArray(draft.entries)
    ? draft.entries.filter((entry) => entry && typeof entry === 'object' && Number(entry.amount) > 0)
    : [];
  expenseNote = typeof draft.note === 'string' ? draft.note.slice(0, 60) : '';
  expenseDefaultBuyerId = String(draft.defaultBuyerId || expenseDefaultBuyerId || '');
  const noteInput = document.getElementById('expenseNoteInput');
  const noteRow = document.getElementById('expenseNoteRow');
  const noteValue = document.getElementById('expenseNoteVal');
  if (noteInput) noteInput.value = expenseNote;
  if (noteRow) noteRow.classList.toggle('hidden', !expenseNote);
  if (noteValue) noteValue.textContent = expenseNote;
  updateBudgetIQExpenseDraftStatus('Draft restored');
  return true;
}

function formatExpenseAED(value) {
  const amount = Math.max(0, Number(value) || 0);
  return `AED ${amount.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 2 })}`;
}

function escapeBudgetIQHtml(value) {
  return String(value ?? '')
    .replaceAll('&', '&amp;')
    .replaceAll('<', '&lt;')
    .replaceAll('>', '&gt;')
    .replaceAll('"', '&quot;')
    .replaceAll("'", '&#039;');
}

function getBudgetIQBuyerMembers() {
  let ids = [];
  let names = {};
  try {
    const savedIds = JSON.parse(localStorage.getItem('budgetiq-member-ids') || '[]');
    const savedNames = JSON.parse(localStorage.getItem('budgetiq-member-names') || '{}');
    if (Array.isArray(savedIds) && savedIds.length) ids = [...new Set(savedIds.map(String).filter(Boolean))];
    if (savedNames && typeof savedNames === 'object' && !Array.isArray(savedNames)) names = savedNames;
  } catch (error) {
    // Keep the buyer list empty when saved member data is unavailable.
  }
  return ids.map((id, index) => ({
    id,
    name: typeof names[id] === 'string' && names[id].trim()
      ? names[id].trim()
      : `Member ${String(index + 1).padStart(2, '0')}`
  }));
}

function getBudgetIQBuyerById(memberId) {
  return getBudgetIQBuyerMembers().find((member) => member.id === String(memberId || '')) || null;
}

function getBudgetIQBuyerName(memberId, fallback = 'Not recorded') {
  return getBudgetIQBuyerById(memberId)?.name || fallback;
}

