function readExpenseReceiptItems() {
  const receipts = expenseEntries
    .filter((entry) => entry.receiptData)
    .map((entry) => ({
      name: entry.name,
      amount: entry.amount,
      receiptData: entry.receiptData,
      receiptName: entry.receiptName,
      detail: `${entry.buyerName || getBudgetIQBuyerName(entry.buyerId)} · Current expense`
    }));

  try {
    const records = JSON.parse(localStorage.getItem(BUDGETIQ_EXPENSES_KEY) || '[]');
    if (!Array.isArray(records)) return receipts;
    records.forEach((record) => {
      const createdAt = new Date(record?.createdAt || '');
      const detail = Number.isNaN(createdAt.getTime())
        ? (record?.month || 'Saved expense')
        : createdAt.toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' });
      const items = Array.isArray(record?.items) ? record.items : [];
      items.forEach((item) => {
        if (!item?.receiptData) return;
        receipts.push({
          name: item.name || 'Expense receipt',
          amount: Number(item.amount) || 0,
          receiptData: item.receiptData,
          receiptName: item.receiptName || 'Receipt picture',
          detail: `${item.buyerName || getBudgetIQBuyerName(item.buyerId)} · ${detail}`
        });
      });
    });
  } catch (error) {
    // Keep any receipts from the current expense when saved history is unavailable.
  }

  return receipts.reverse();
}

function refreshExpenseReceiptCard() {
  const countLabel = document.getElementById('receiptCountLabel');
  if (!countLabel) return;
  const count = readExpenseReceiptItems().length;
  countLabel.textContent = count ? `${count} Receipt${count === 1 ? '' : 's'}` : 'No receipts yet';
}

