function refreshExpenseSummaryCards() {
  const spentLabel = document.getElementById('moneySpentVal');
  const leftLabel = document.getElementById('moneyLeftVal');
  const balanceAfterExpenseLabel = document.getElementById('balanceAfterExpenseVal');
  if (!spentLabel || !leftLabel) return;

  const collected = readBudgetIQCollectedTotal();
  const draftTotal = expenseEntries.reduce((sum, entry) => sum + (Number(entry.amount) || 0), 0);
  const spent = BUDGETIQ_FIXED_EXPENSES + readBudgetIQRecordedExpenseTotal() + draftTotal;
  const left = collected - spent;
  spentLabel.textContent = formatBudgetIQAED(spent);
  leftLabel.textContent = formatBudgetIQAED(left);
  if (balanceAfterExpenseLabel) balanceAfterExpenseLabel.textContent = formatBudgetIQAED(left);
}

function readExpenseSpendingBreakdown() {
  const savedItems = [];
  const liveNoteInput = document.getElementById('expenseNoteInput');
  const currentNote = liveNoteInput ? liveNoteInput.value.trim() : expenseNote;
  const currentItems = expenseEntries
    .filter((entry) => (Number(entry.amount) || 0) > 0)
    .map((entry) => ({
      name: entry.name || 'Current expense',
      category: EXPENSE_CATEGORY_CONFIG[entry.category] ? entry.category : 'other',
      amount: Number(entry.amount) || 0,
      buyerId: entry.buyerId || '',
      buyerName: entry.buyerName || getBudgetIQBuyerName(entry.buyerId),
      detail: 'Pending final save',
      note: currentNote
    }))
    .reverse();

  try {
    const records = JSON.parse(localStorage.getItem(BUDGETIQ_EXPENSES_KEY) || '[]');
    if (Array.isArray(records)) {
      records.forEach((record) => {
        if (record?.month !== getBudgetIQExpenseDraftMonth()) return;
        const items = Array.isArray(record?.items) ? record.items : [];
        let listedTotal = 0;

        items.forEach((item) => {
          const amount = Number(item?.amount) || 0;
          if (amount <= 0) return;
          listedTotal += amount;
          savedItems.push({
            name: item.name || 'Saved expense',
            category: EXPENSE_CATEGORY_CONFIG[item.category] ? item.category : 'other',
            amount,
            buyerId: item.buyerId || '',
            buyerName: item.buyerName || getBudgetIQBuyerName(item.buyerId),
            detail: record?.month || 'Saved expense',
            note: record?.note || ''
          });
        });

        const recordTotal = Number(record?.amount) || 0;
        if (recordTotal > listedTotal) {
          savedItems.push({
            name: record?.note || 'Other saved expense',
            category: 'other',
            amount: recordTotal - listedTotal,
            buyerId: '',
            buyerName: 'Not recorded',
            detail: record?.month || 'Saved expense',
            note: ''
          });
        }
      });
    }
  } catch (error) {
    // Show the opening expense record when saved expense history is unavailable.
  }

  savedItems.reverse();
  if (BUDGETIQ_FIXED_EXPENSES > 0) {
    savedItems.push({
      name: 'Previous recorded expenses',
      category: 'other',
      amount: BUDGETIQ_FIXED_EXPENSES,
      buyerId: '',
      buyerName: 'Not recorded',
      detail: 'Opening expense record',
      note: ''
    });
  }
  return [...currentItems, ...savedItems];
}

function renderExpenseSpendingBreakdown() {
  const list = document.getElementById('spendingBreakdownList');
  const totalLabel = document.getElementById('spendingBreakdownTotal');
  if (!list || !totalLabel) return;

  const items = readExpenseSpendingBreakdown();
  const total = items.reduce((sum, item) => sum + (Number(item.amount) || 0), 0);
  list.innerHTML = items.map((item) => {
    const category = EXPENSE_CATEGORY_CONFIG[item.category] || EXPENSE_CATEGORY_CONFIG.other;
    return `
      <div class="flex items-center gap-3 rounded-xl border border-zinc-800 bg-zinc-900/60 p-3">
        <span class="flex h-9 w-9 shrink-0 items-center justify-center rounded-xl bg-white/[0.04] text-zinc-400">
          <span class="material-icons text-base">${category.icon}</span>
        </span>
        <div class="min-w-0 flex-1">
          <h3 class="truncate text-[10px] font-extrabold uppercase tracking-wider text-white">${escapeBudgetIQHtml(item.name)}</h3>
          <p class="mt-0.5 truncate text-[8px] font-semibold text-zinc-500">${escapeBudgetIQHtml(item.buyerName || 'Not recorded')} · ${escapeBudgetIQHtml(category.label)} · ${escapeBudgetIQHtml(item.detail)}</p>
        </div>
        <span class="shrink-0 text-[10px] font-black text-[#C1FF72]">${formatExpenseAED(item.amount)}</span>
      </div>`;
  }).join('');
  totalLabel.textContent = formatExpenseAED(total);
}

