function showExpenseEditorError(message) {
  const errorLabel = document.getElementById('expenseEditorError');
  if (!errorLabel) return;
  errorLabel.textContent = message;
  errorLabel.classList.toggle('hidden', !message);
}

function updateExpenseReceiptPreview() {
  const preview = document.getElementById('expenseReceiptPreview');
  const image = document.getElementById('expenseReceiptPreviewImage');
  const fileName = document.getElementById('expenseReceiptFileName');
  if (preview) {
    preview.classList.toggle('hidden', !expenseReceiptData);
    preview.classList.toggle('flex', Boolean(expenseReceiptData));
  }
  if (image) image.src = expenseReceiptData || '';
  if (fileName) fileName.textContent = expenseReceiptName || 'Receipt picture';
}

function updateExpenseBuyerField() {
  const value = document.getElementById('expenseBuyerValue');
  const buyer = getBudgetIQBuyerById(expenseEditorBuyerId);
  if (value) value.textContent = buyer ? buyer.name : 'Select buyer';
}

function refreshExpenseBuyerDescription() {
  const desc = document.getElementById('buyerDesc');
  if (!desc) return;
  const buyer = getBudgetIQBuyerById(expenseDefaultBuyerId);
  desc.textContent = buyer
    ? `👤 Current buyer: ${buyer.name}. New expenses will use this buyer.`
    : '👤 Select who purchased each expense.';
}

function openExpenseEditor(entryId = null) {
  if (!requireBudgetIQPermission('expenses', 'manage expenses')) return;
  const modal = document.getElementById('expenseEditorModal');
  const title = document.getElementById('expenseEditorTitle');
  const nameInput = document.getElementById('expenseNameInput');
  const categoryInput = document.getElementById('expenseCategoryInput');
  const amountInput = document.getElementById('expenseAmountInput');
  const receiptInput = document.getElementById('expenseReceiptInput');
  if (!modal || !nameInput || !categoryInput || !amountInput) return;

  const entry = expenseEntries.find((item) => item.id === entryId) || null;
  expenseEditingId = entry ? entry.id : null;
  expenseReceiptData = entry?.receiptData || '';
  expenseReceiptName = entry?.receiptName || '';
  expenseEditorBuyerId = entry?.buyerId || expenseDefaultBuyerId || '';
  if (title) title.textContent = entry ? 'Edit expense' : 'Add expense';
  nameInput.value = entry?.name || '';
  categoryInput.value = entry?.category || 'other';
  amountInput.value = entry?.amount || '';
  if (receiptInput) receiptInput.value = '';
  showExpenseEditorError('');
  updateExpenseReceiptPreview();
  updateExpenseBuyerField();

  modal.classList.remove('hidden');
  modal.classList.add('flex');
  document.body.style.overflow = 'hidden';
  setTimeout(() => nameInput.focus(), 80);
}

function closeExpenseEditor() {
  const modal = document.getElementById('expenseEditorModal');
  if (modal) {
    modal.classList.add('hidden');
    modal.classList.remove('flex');
  }
  document.body.style.overflow = '';
  expenseEditingId = null;
  expenseEditorBuyerId = '';
  expenseReceiptData = '';
  expenseReceiptName = '';
  showExpenseEditorError('');
}

function saveExpenseEntry(event) {
  event.preventDefault();
  if (!requireBudgetIQPermission('expenses', 'manage expenses')) return;
  const nameInput = document.getElementById('expenseNameInput');
  const categoryInput = document.getElementById('expenseCategoryInput');
  const amountInput = document.getElementById('expenseAmountInput');
  const name = nameInput?.value.trim() || '';
  const category = EXPENSE_CATEGORY_CONFIG[categoryInput?.value] ? categoryInput.value : 'other';
  const amount = Math.round((Number(amountInput?.value) || 0) * 100) / 100;
  const buyer = getBudgetIQBuyerById(expenseEditorBuyerId);

  if (!name) {
    showExpenseEditorError('Enter an expense name.');
    nameInput?.focus();
    return;
  }
  if (amount <= 0) {
    showExpenseEditorError('Enter an amount greater than AED 0.');
    amountInput?.focus();
    return;
  }
  if (!buyer) {
    showExpenseEditorError('Select who purchased this expense.');
    updateExpenseBuyerField();
    return;
  }
  const otherReceiptCount = expenseEntries.filter((entry) => entry.id !== expenseEditingId && entry.receiptData).length;
  if (expenseReceiptData && otherReceiptCount >= 10) {
    showExpenseEditorError('You can attach up to 10 receipts to one saved expense.');
    return;
  }

  const nextEntry = {
    id: expenseEditingId || `expense-entry-${Date.now()}`,
    name,
    category,
    amount,
    buyerId: buyer.id,
    buyerName: buyer.name,
    receiptData: expenseReceiptData || '',
    receiptName: expenseReceiptData ? (expenseReceiptName || 'Receipt picture') : ''
  };

  const existingIndex = expenseEntries.findIndex((entry) => entry.id === expenseEditingId);
  if (existingIndex >= 0) expenseEntries.splice(existingIndex, 1, nextEntry);
  else expenseEntries.push(nextEntry);

  expenseDefaultBuyerId = buyer.id;

  closeExpenseEditor();
  renderExpenseEntries();
  refreshExpenseSummaryCards();
  refreshExpenseBuyerDescription();
  saveBudgetIQExpenseDraft();
}

function removeExpenseEntry(entryId) {
  if (!requireBudgetIQPermission('expenses', 'remove expenses')) return;
  const entry = expenseEntries.find((item) => item.id === entryId);
  if (!entry || !window.confirm(`Remove ${entry.name}?`)) return;
  expenseEntries = expenseEntries.filter((item) => item.id !== entryId);
  renderExpenseEntries();
  refreshExpenseSummaryCards();
  saveBudgetIQExpenseDraft();
}

function compressExpenseReceipt(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onerror = () => reject(new Error('Could not read this picture.'));
    reader.onload = () => {
      const image = new Image();
      image.onerror = () => reject(new Error('This picture format is not supported.'));
      image.onload = () => {
        const maxDimension = 900;
        const targetLength = 380000;
        let scale = Math.min(1, maxDimension / Math.max(image.width, image.height));
        const canvas = document.createElement('canvas');
        const context = canvas.getContext('2d');
        if (!context) {
          reject(new Error('Picture processing is unavailable.'));
          return;
        }

        let compressed = '';
        for (let resizeAttempt = 0; resizeAttempt < 4 && !compressed; resizeAttempt += 1) {
          canvas.width = Math.max(1, Math.round(image.width * scale));
          canvas.height = Math.max(1, Math.round(image.height * scale));
          context.fillStyle = '#FFFFFF';
          context.fillRect(0, 0, canvas.width, canvas.height);
          context.drawImage(image, 0, 0, canvas.width, canvas.height);
          for (const quality of [0.72, 0.62, 0.52, 0.44]) {
            const candidate = canvas.toDataURL('image/jpeg', quality);
            if (candidate.length <= targetLength) {
              compressed = candidate;
              break;
            }
          }
          scale *= 0.8;
        }
        if (!compressed) compressed = canvas.toDataURL('image/jpeg', 0.4);
        if (compressed.length > 450000) {
          reject(new Error('This picture is still too large after compression.'));
          return;
        }
        resolve(compressed);
      };
      image.src = String(reader.result || '');
    };
    reader.readAsDataURL(file);
  });
}

async function handleExpenseReceiptUpload(event) {
  const file = event.target.files?.[0];
  const saveButton = document.getElementById('expenseEditorSaveButton');
  if (!file) return;
  if (!file.type.startsWith('image/')) {
    showExpenseEditorError('Choose a JPG, PNG, or other image file.');
    event.target.value = '';
    return;
  }
  if (file.size > 8 * 1024 * 1024) {
    showExpenseEditorError('Receipt pictures must be smaller than 8 MB.');
    event.target.value = '';
    return;
  }

  if (saveButton) {
    saveButton.disabled = true;
    saveButton.textContent = 'Processing';
  }
  showExpenseEditorError('');
  try {
    expenseReceiptData = await compressExpenseReceipt(file);
    expenseReceiptName = file.name;
    updateExpenseReceiptPreview();
  } catch (error) {
    expenseReceiptData = '';
    expenseReceiptName = '';
    updateExpenseReceiptPreview();
    showExpenseEditorError(error.message || 'Could not attach this picture.');
  } finally {
    if (saveButton) {
      saveButton.disabled = false;
      saveButton.textContent = 'Save Entry';
    }
  }
}

function removeExpenseReceipt() {
  const receiptInput = document.getElementById('expenseReceiptInput');
  expenseReceiptData = '';
  expenseReceiptName = '';
  if (receiptInput) receiptInput.value = '';
  updateExpenseReceiptPreview();
}

function renderBuyerSelectionMembers() {
  const list = document.getElementById('buyerSelectionList');
  if (!list) return;
  const members = getBudgetIQBuyerMembers();
  list.innerHTML = members.length ? members.map((member, index) => `
    <label class="flex cursor-pointer items-center gap-2.5 rounded-xl border border-zinc-800 bg-zinc-900/60 px-3 py-2 transition-all hover:border-purple-500/30">
      <input type="radio" name="expenseBuyer" value="${escapeBudgetIQHtml(member.id)}"
        ${expensePendingBuyerId === member.id ? 'checked' : ''} onchange="selectPendingExpenseBuyer('${escapeBudgetIQHtml(member.id)}')"
        class="buyer-radio h-4 w-4 accent-[#C1FF72]" />
      <span class="flex h-8 w-8 items-center justify-center rounded-xl bg-purple-500/10 text-[9px] font-black text-purple-400">M${index + 1}</span>
      <span class="min-w-0 flex-1 truncate text-[10px] font-bold text-white">${escapeBudgetIQHtml(member.name)}</span>
    </label>`).join('') : `
    <div class="rounded-2xl border border-dashed border-zinc-800 bg-zinc-900/40 px-5 py-8 text-center">
      <span class="material-icons text-2xl text-zinc-700">group_add</span>
      <p class="mt-2 text-[9px] font-black uppercase tracking-wider text-zinc-500">No members available</p>
      <p class="mt-1 text-[8px] font-semibold text-zinc-600">Add a member before recording an expense.</p>
    </div>`;
}

function selectPendingExpenseBuyer(memberId) {
  expensePendingBuyerId = String(memberId || '');
  const errorLabel = document.getElementById('buyerSelectionError');
  if (errorLabel) errorLabel.classList.add('hidden');
}

function openBuyerSelectionModal(target = 'default') {
  const modal = document.getElementById('buyerSelectionModal');
  if (!modal) return;
  expenseBuyerSelectionTarget = target === 'editor' ? 'editor' : 'default';
  expensePendingBuyerId = expenseBuyerSelectionTarget === 'editor'
    ? expenseEditorBuyerId
    : expenseDefaultBuyerId;
  const errorLabel = document.getElementById('buyerSelectionError');
  if (errorLabel) errorLabel.classList.add('hidden');
  renderBuyerSelectionMembers();
  modal.classList.remove('hidden');
  modal.classList.add('flex');
  document.body.style.overflow = 'hidden';
}

function closeBuyerSelectionModal() {
  const modal = document.getElementById('buyerSelectionModal');
  if (modal) {
    modal.classList.add('hidden');
    modal.classList.remove('flex');
  }
  document.body.style.overflow = expenseBuyerSelectionTarget === 'editor' ? 'hidden' : '';
}

function saveBuyerSelection() {
  const selected = document.querySelector('.buyer-radio:checked');
  const selectedId = selected?.value || expensePendingBuyerId;
  const buyer = getBudgetIQBuyerById(selectedId);
  const errorLabel = document.getElementById('buyerSelectionError');
  if (!buyer) {
    if (errorLabel) errorLabel.classList.remove('hidden');
    return;
  }

  if (expenseBuyerSelectionTarget === 'editor') {
    expenseEditorBuyerId = buyer.id;
    updateExpenseBuyerField();
    showExpenseEditorError('');
  } else {
    expenseDefaultBuyerId = buyer.id;
    refreshExpenseBuyerDescription();
    recalculateBill();
    saveBudgetIQExpenseDraft();
  }
  closeBuyerSelectionModal();
}

function renderPurchaseHistory() {
  const list = document.getElementById('purchaseHistoryList');
  const totalLabel = document.getElementById('purchaseHistoryTotal');
  if (!list || !totalLabel) return;
  const items = readExpenseSpendingBreakdown();
  const total = items.reduce((sum, item) => sum + (Number(item.amount) || 0), 0);

  list.innerHTML = items.map((item) => {
    const category = EXPENSE_CATEGORY_CONFIG[item.category] || EXPENSE_CATEGORY_CONFIG.other;
    const buyerName = item.buyerName || 'Not recorded';
    const initials = buyerName === 'Not recorded'
      ? '?'
      : buyerName.split(/\s+/).map((part) => part[0]).join('').slice(0, 2).toUpperCase();
    return `
      <div class="rounded-xl border border-zinc-800 bg-zinc-900/60 p-3">
        <div class="flex items-center gap-3">
          <span class="flex h-9 w-9 shrink-0 items-center justify-center rounded-xl bg-sky-500/10 text-[9px] font-black text-sky-400">${escapeBudgetIQHtml(initials)}</span>
          <div class="min-w-0 flex-1">
            <h3 class="truncate text-[10px] font-extrabold uppercase tracking-wider text-white">${escapeBudgetIQHtml(item.name)}</h3>
            <p class="mt-0.5 truncate text-[8px] font-semibold text-zinc-500">${escapeBudgetIQHtml(category.label)} · ${escapeBudgetIQHtml(item.detail)}</p>
          </div>
          <span class="shrink-0 text-[10px] font-black text-[#C1FF72]">${formatExpenseAED(item.amount)}</span>
        </div>
        <div class="mt-2 flex items-center gap-1.5 border-t border-white/[0.04] pt-2 text-[8px] font-bold text-zinc-500">
          <span class="material-icons text-[12px] text-sky-400">person</span>
          Purchased by <span class="text-zinc-300">${escapeBudgetIQHtml(buyerName)}</span>
        </div>
      </div>`;
  }).join('');
  totalLabel.textContent = formatExpenseAED(total);
}

