function applyExpenseNote() {
  const noteInput = document.getElementById('expenseNoteInput');
  const noteRow = document.getElementById('expenseNoteRow');
  const noteValue = document.getElementById('expenseNoteVal');
  if (!noteInput) return;

  expenseNote = noteInput.value.trim();
  if (noteRow) noteRow.classList.toggle('hidden', !expenseNote);
  if (noteValue) noteValue.textContent = expenseNote || '';
  saveBudgetIQExpenseDraft();
}

function recalculateBill() {
  const subtotal = expenseEntries.reduce((total, entry) => total + (Number(entry.amount) || 0), 0);

  const subtotalVal = document.getElementById('subtotalVal');
  const buyerSummaryVal = document.getElementById('purchaseBuyerSummaryVal');
  const saveButton = document.getElementById('saveExpenseButton');
  const saveButtonLabel = document.getElementById('saveExpenseButtonLabel');
  const saveButtonIcon = document.getElementById('saveExpenseButtonIcon');

  if (subtotalVal) subtotalVal.innerText = formatExpenseAED(subtotal);
  if (buyerSummaryVal) {
    const buyerNames = [...new Set(expenseEntries.map((entry) => entry.buyerName).filter(Boolean))];
    buyerSummaryVal.innerText = buyerNames.length === 0
      ? (getBudgetIQBuyerName(expenseDefaultBuyerId, 'Not selected'))
      : buyerNames.length === 1 ? buyerNames[0] : `${buyerNames.length} Buyers`;
  }
  if (saveButton) {
    const canSave = subtotal > 0;
    saveButton.disabled = !canSave;
    saveButton.setAttribute('aria-disabled', String(!canSave));
    saveButton.className = canSave
      ? 'w-full bg-[#C1FF72] hover:bg-[#b0f55c] active:scale-[0.98] text-black font-extrabold py-4 rounded-2xl shadow-[0_8px_30px_rgba(193,255,114,0.1)] transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-widest group'
      : 'w-full cursor-not-allowed bg-zinc-800 text-zinc-500 font-extrabold py-4 rounded-2xl transition-all flex items-center justify-center gap-2 text-xs uppercase tracking-widest group';
    if (saveButtonLabel) saveButtonLabel.textContent = canSave ? `Save ${formatExpenseAED(subtotal)} Expense` : 'Add an expense first';
    if (saveButtonIcon) {
      saveButtonIcon.textContent = canSave ? 'check_circle' : 'add_circle';
      saveButtonIcon.className = canSave
        ? 'material-icons text-sm transition-transform group-hover:translate-x-1'
        : 'material-icons text-sm transition-transform';
    }
  }
}

function openExpenseSavedModal(amount, buyers) {
  const modal = document.getElementById('expenseSavedModal');
  const amountLabel = document.getElementById('expenseSavedAmount');
  const buyerLabel = document.getElementById('expenseSavedBuyer');
  const monthLabel = document.getElementById('expenseSavedMonth');
  if (!modal) return;

  const linkedBuyers = Array.isArray(buyers) ? buyers.filter((buyer) => buyer?.name) : [];
  const buyerText = linkedBuyers.length === 1
    ? linkedBuyers[0].name
    : linkedBuyers.length > 1 ? `${linkedBuyers.length} buyers` : 'Shared fund';

  if (amountLabel) amountLabel.textContent = formatExpenseAED(amount);
  if (buyerLabel) buyerLabel.textContent = buyerText;
  if (monthLabel) monthLabel.textContent = `${getBudgetIQCurrentMonthName()} • Visible to all fund users`;
  modal.classList.remove('hidden');
  modal.classList.add('flex');
  document.body.style.overflow = 'hidden';
}

function closeExpenseSavedModal(event) {
  const modal = document.getElementById('expenseSavedModal');
  if (!modal || (event && event.target !== modal)) return;
  modal.classList.add('hidden');
  modal.classList.remove('flex');
  document.body.style.overflow = '';
}

function triggerSaveExpense() {
  if (!requireBudgetIQPermission('expenses', 'save expenses')) return;
  const total = expenseEntries.reduce((sum, entry) => sum + (Number(entry.amount) || 0), 0);
  if (total <= 0) {
    alert('Add at least one expense entry before saving.');
    return;
  }

  const noteInput = document.getElementById('expenseNoteInput');
  if (noteInput) expenseNote = noteInput.value.trim();

  const buyers = [...new Map(expenseEntries.map((entry) => [entry.buyerId, {
    id: entry.buyerId,
    name: entry.buyerName
  }])).values()];
  const expenseRecord = {
    id: `expense-${Date.now()}`,
    createdAt: new Date().toISOString(),
    month: 'July 2026',
    actor: getBudgetIQCurrentActorName(),
    buyers,
    note: expenseNote,
    amount: total,
    items: expenseEntries.map((entry) => ({
      name: entry.name,
      category: entry.category,
      amount: entry.amount,
      buyerId: entry.buyerId,
      buyerName: entry.buyerName,
      receiptName: entry.receiptName || '',
      receiptData: entry.receiptData || ''
    }))
  };

  try {
    expenseRecord.month = localStorage.getItem('budgetiq-selected-month') || expenseRecord.month;
    const savedExpenses = JSON.parse(localStorage.getItem(BUDGETIQ_EXPENSES_KEY) || '[]');
    const expenses = Array.isArray(savedExpenses) ? savedExpenses : [];
    expenses.push(expenseRecord);
    localStorage.setItem(BUDGETIQ_EXPENSES_KEY, JSON.stringify(expenses));
    renderBudgetIQNotificationBadges();
  } catch (error) {
    alert('The expense was not saved. Your draft is still safe. Export a backup or remove large receipt pictures, then try again.');
    saveBudgetIQExpenseDraft();
    return;
  }

  expenseEntries = [];
  expenseNote = '';
  if (noteInput) noteInput.value = '';
  const noteRow = document.getElementById('expenseNoteRow');
  const noteValue = document.getElementById('expenseNoteVal');
  if (noteRow) noteRow.classList.add('hidden');
  if (noteValue) noteValue.textContent = '';
  saveBudgetIQExpenseDraft();
  renderExpenseEntries();
  refreshExpenseSummaryCards();
  refreshExpenseReceiptCard();

  openExpenseSavedModal(total, buyers);
}

function initializeBudgetIQExpenseEntry() {
  if (!document.getElementById('subtotalVal')) return;
  restoreBudgetIQExpenseDraft();
  renderExpenseEntries();
  refreshExpenseBuyerDescription();
  const noteInput = document.getElementById('expenseNoteInput');
  noteInput?.addEventListener('input', scheduleBudgetIQExpenseDraftSave);
  window.addEventListener('pagehide', saveBudgetIQExpenseDraft);
  setTimeout(() => {
    refreshExpenseSummaryCards();
    refreshExpenseReceiptCard();
  }, 0);
}

