function showNotification(message) {
  closeDriveInModal();
  closeLoyaltyModal();
  closeMonthSheet();

  if (indexToastText && indexToastNotification) {
    indexToastText.innerText = message;
    indexToastNotification.classList.remove('opacity-0', 'pointer-events-none', 'translate-y-3');
    indexToastNotification.classList.add('opacity-100', 'translate-y-0');

    clearTimeout(indexToastTimeout);
    indexToastTimeout = setTimeout(() => {
      indexToastNotification.classList.add('opacity-0', 'pointer-events-none', 'translate-y-3');
      indexToastNotification.classList.remove('opacity-100', 'translate-y-0');
    }, 2500);
  } else {
    // Fallback to global toast system if index-specific elements are absent
    showToast(message, 'location_on', 'text-[#C1FF72]');
  }
}

