function readBudgetIQMonthlyPaymentRecords() {
  try {
    const records = JSON.parse(localStorage.getItem(MEMBER_MONTHLY_PAYMENTS_KEY) || '{}');
    return records && typeof records === 'object' && !Array.isArray(records) ? records : {};
  } catch (error) {
    return {};
  }
}

function readBudgetIQPaymentsForMonth(month = getBudgetIQCurrentMonthName()) {
  const records = readBudgetIQMonthlyPaymentRecords();
  const payments = records[month];
  return payments && typeof payments === 'object' && !Array.isArray(payments) ? payments : {};
}

function createBudgetIQMemberRow(id, name, paid = false) {
  if (!memberScrollList) return null;
  const row = document.createElement('div');
  row.className = 'member-list-row flex items-center gap-3 border-b border-white/[0.055] py-3';
  row.dataset.memberId = String(id);
  row.dataset.status = paid ? 'paid' : 'unpaid';

  const avatarStyles = [
    'bg-[#C1FF72]/10 text-[#C1FF72]',
    'bg-emerald-400/10 text-emerald-400',
    'bg-sky-500/10 text-sky-400',
    'bg-purple-500/10 text-purple-400',
    'bg-amber-500/10 text-amber-400',
    'bg-pink-500/10 text-pink-400',
    'bg-cyan-500/10 text-cyan-400',
    'bg-indigo-500/10 text-indigo-400',
    'bg-orange-500/10 text-orange-400',
    'bg-red-500/10 text-red-400'
  ];
  const avatarStyle = avatarStyles[(Number(id) - 1) % avatarStyles.length];

  row.innerHTML = `
    <span class="flex h-9 w-9 shrink-0 items-center justify-center rounded-xl ${avatarStyle} text-[10px] font-black">M${id}</span>
    <span class="member-name min-w-0 flex-1 truncate text-xs font-extrabold text-white"></span>
    <button type="button" onclick="toggleMemberPaid(this)" aria-label="Mark member paid or not paid" aria-pressed="false"
      class="member-payment-toggle flex h-7 w-7 shrink-0 items-center justify-center rounded-lg border border-red-500/25 bg-red-500/10 text-red-400 transition-all active:scale-90">
      <span class="material-icons text-base">close</span>
    </button>`;
  const nameElement = row.querySelector('.member-name');
  if (nameElement) nameElement.textContent = name;
  memberScrollList.appendChild(row);
  budgetIQMemberRows.push(row);
  setMemberPaymentAppearance(row, paid);
  return row;
}

