function setMemberPaymentAppearance(row, paid) {
  if (!row) return;
  const button = row.querySelector('.member-payment-toggle');
  if (!button) return;

  row.dataset.status = paid ? 'paid' : 'unpaid';
  button.setAttribute('aria-pressed', paid ? 'true' : 'false');
  button.className = paid
    ? 'member-payment-toggle flex h-7 w-7 shrink-0 items-center justify-center rounded-lg border border-[#C1FF72]/30 bg-[#C1FF72] text-black transition-all active:scale-90'
    : 'member-payment-toggle flex h-7 w-7 shrink-0 items-center justify-center rounded-lg border border-red-500/25 bg-red-500/10 text-red-400 transition-all active:scale-90';

  const icon = button.querySelector('.material-icons');
  if (icon) icon.innerText = paid ? 'check' : 'close';
}

function updateMemberPaymentSummary() {
  const paid = budgetIQMemberRows.filter((row) => row.dataset.status === 'paid').length;
  const unpaid = budgetIQMemberRows.length - paid;
  const paymentPercent = budgetIQMemberRows.length
    ? Math.round((paid / budgetIQMemberRows.length) * 100)
    : 0;
  if (memberTotalCount) memberTotalCount.innerText = String(budgetIQMemberRows.length);
  if (memberPaidCount) memberPaidCount.innerText = String(paid);
  if (memberUnpaidCount) memberUnpaidCount.innerText = String(unpaid);
  if (memberPaidProgress) memberPaidProgress.style.width = `${paymentPercent}%`;
  if (memberEmptyState) memberEmptyState.classList.toggle('hidden', budgetIQMemberRows.length > 0);
  const contributionTypeLabel = document.getElementById('memberContributionTypeLabel');
  const contributionLabel = document.getElementById('memberContributionAmount');
  const collectedLabel = document.getElementById('memberCollectedAmount');
  const groupPlan = readBudgetIQContributionGroupPlan();
  const memberAmounts = budgetIQMemberRows.map((row) => readBudgetIQContributionForMember(row.dataset.memberId));
  const assignedAmounts = memberAmounts.filter((amount) => amount > 0);
  const collected = budgetIQMemberRows.reduce((total, row, index) => (
    total + (row.dataset.status === 'paid' ? memberAmounts[index] : 0)
  ), 0);

  if (contributionTypeLabel) {
    contributionTypeLabel.textContent = groupPlan
      ? `${groupPlan.length} payment ${groupPlan.length === 1 ? 'group' : 'groups'}`
      : 'Per member';
  }
  if (contributionLabel) {
    if (groupPlan && assignedAmounts.length) {
      const minimum = Math.min(...assignedAmounts);
      const maximum = Math.max(...assignedAmounts);
      contributionLabel.textContent = minimum === maximum
        ? formatBudgetIQAED(minimum)
        : `${formatBudgetIQAED(minimum)} – ${maximum.toLocaleString('en-US')}`;
    } else {
      contributionLabel.textContent = formatBudgetIQAED(readBudgetIQContributionPerMember());
    }
  }
  if (collectedLabel) collectedLabel.textContent = formatBudgetIQAED(collected);

  budgetIQMemberRows.forEach((row, index) => {
    let amountLabel = row.querySelector('.member-contribution-amount');
    if (!amountLabel) {
      amountLabel = document.createElement('span');
      amountLabel.className = 'member-contribution-amount shrink-0 rounded-lg border border-white/[0.06] bg-black/20 px-2 py-1 text-[8px] font-black text-zinc-500';
      row.querySelector('.member-payment-toggle')?.before(amountLabel);
    }
    if (amountLabel) {
      amountLabel.textContent = memberAmounts[index] > 0 ? formatBudgetIQAED(memberAmounts[index]) : 'Not set';
      amountLabel.classList.toggle('text-zinc-500', memberAmounts[index] > 0);
      amountLabel.classList.toggle('text-amber-400', memberAmounts[index] <= 0);
    }
  });
}

function saveBudgetIQMembers() {
  if (!budgetIQMemberRows.length) return false;
  const names = {};
  const payments = {};
  const ids = [];
  budgetIQMemberRows.forEach((row) => {
    const id = row.dataset.memberId;
    if (id) ids.push(id);
    const name = row.querySelector('.member-name');
    if (id && name) names[id] = name.innerText.trim();
    if (id) payments[id] = row.dataset.status === 'paid';
  });
  try {
    localStorage.setItem(MEMBER_NAMES_KEY, JSON.stringify(names));
    localStorage.setItem(MEMBER_IDS_KEY, JSON.stringify(ids));
    const monthlyPayments = readBudgetIQMonthlyPaymentRecords();
    monthlyPayments[getBudgetIQCurrentMonthName()] = payments;
    localStorage.setItem(MEMBER_MONTHLY_PAYMENTS_KEY, JSON.stringify(monthlyPayments));
    // Keep the legacy key aligned for old cached pages during this upgrade.
    localStorage.setItem(MEMBER_PAYMENTS_KEY, JSON.stringify(payments));
    return true;
  } catch (error) {
    triggerToast('Not saved — iPhone storage is unavailable', 'error', 'text-red-400');
    return false;
  }
}

function recordBudgetIQContributionActivity(memberId, memberName, paid) {
  try {
    const records = JSON.parse(localStorage.getItem(BUDGETIQ_CONTRIBUTION_ACTIVITY_KEY) || '[]');
    const activity = Array.isArray(records) ? records : [];
    const contributionAmount = readBudgetIQContributionForMember(memberId);
    activity.push({
      id: `contribution-${Date.now()}-${memberId}`,
      createdAt: new Date().toISOString(),
      month: localStorage.getItem('budgetiq-selected-month') || 'July 2026',
      memberId: String(memberId || ''),
      memberName: memberName || 'Member',
      amount: paid ? contributionAmount : -contributionAmount,
      status: paid ? 'Paid' : 'Reversed',
      actor: getBudgetIQCurrentActorName()
    });
    localStorage.setItem(BUDGETIQ_CONTRIBUTION_ACTIVITY_KEY, JSON.stringify(activity));
    renderBudgetIQNotificationBadges();
    return true;
  } catch (error) {
    triggerToast('Payment saved, but its history entry was not saved', 'warning', 'text-amber-400');
    return false;
  }
}

function loadBudgetIQMembers() {
  if (!memberScrollList) return;
  let names = {};
  let payments = {};
  let savedIds = [];
  try {
    names = JSON.parse(localStorage.getItem(MEMBER_NAMES_KEY) || '{}');
    payments = readBudgetIQPaymentsForMonth();
    savedIds = JSON.parse(localStorage.getItem(MEMBER_IDS_KEY) || '[]');
  } catch (_) {
    names = {};
    payments = {};
    savedIds = [];
  }

  if (Array.isArray(savedIds)) {
    savedIds.forEach((savedId) => {
      const id = String(savedId);
      const alreadyExists = budgetIQMemberRows.some((row) => row.dataset.memberId === id);
      if (!alreadyExists) {
        const fallbackName = `Member ${String(id).padStart(2, '0')}`;
        createBudgetIQMemberRow(id, names[id] || fallbackName, payments[id] === true);
      }
    });
  }

  budgetIQMemberRows.forEach((row) => {
    const id = row.dataset.memberId;
    const name = row.querySelector('.member-name');
    if (id && name && typeof names[id] === 'string' && names[id].trim()) name.innerText = names[id].trim();
    if (id && typeof payments[id] === 'boolean') setMemberPaymentAppearance(row, payments[id]);
    if (editMemberSelect && id) {
      const option = editMemberSelect.querySelector(`option[value="${id}"]`);
      if (option && name) option.innerText = name.innerText;
    }
    if (id && name) addMemberSelectOption(id, name.innerText);
  });
  updateMemberPaymentSummary();
}

function applyBudgetIQMemberPaymentsForMonth() {
  if (!budgetIQMemberRows.length) {
    updateMemberPaymentSummary();
    return;
  }
  const payments = readBudgetIQPaymentsForMonth();
  budgetIQMemberRows.forEach((row) => {
    setMemberPaymentAppearance(row, payments[row.dataset.memberId] === true);
  });
  updateMemberPaymentSummary();
}

function openAddMemberModal() {
  if (!requireBudgetIQPermission('members', 'add members')) return;
  if (!addMemberModal) return;
  if (addMemberNameInput) addMemberNameInput.value = '';
  addMemberModal.classList.remove('hidden');
  requestAnimationFrame(() => {
    addMemberModal.classList.add('opacity-100');
    const panel = addMemberModal.querySelector('.add-member-panel');
    panel?.classList.remove('scale-95');
    panel?.classList.add('scale-100');
  });
  setTimeout(() => addMemberNameInput?.focus(), 180);
}

function closeAddMemberModal(event) {
  if (!addMemberModal) return;
  if (event && event.target !== addMemberModal) return;
  addMemberModal.classList.remove('opacity-100');
  const panel = addMemberModal.querySelector('.add-member-panel');
  panel?.classList.add('scale-95');
  panel?.classList.remove('scale-100');
  setTimeout(() => addMemberModal.classList.add('hidden'), 300);
}

function saveNewMember() {
  if (!requireBudgetIQPermission('members', 'add members')) return;
  if (!addMemberNameInput || !memberScrollList) return;
  const name = addMemberNameInput.value.trim();
  if (!name) {
    triggerToast('Please enter a member name', 'error', 'text-red-400');
    addMemberNameInput.focus();
    return;
  }

  const currentIds = budgetIQMemberRows.map((row) => Number(row.dataset.memberId) || 0);
  const newId = currentIds.length ? Math.max(...currentIds) + 1 : 1;
  const row = createBudgetIQMemberRow(newId, name, false);
  if (!row) return;
  addMemberSelectOption(newId, name);
  if (memberSearchInput) memberSearchInput.value = '';
  filterMemberRows();
  if (!saveBudgetIQMembers()) {
    row.remove();
    const rowIndex = budgetIQMemberRows.indexOf(row);
    if (rowIndex >= 0) budgetIQMemberRows.splice(rowIndex, 1);
    editMemberSelect?.querySelector(`option[value="${newId}"]`)?.remove();
    updateMemberPaymentSummary();
    return;
  }
  updateMemberPaymentSummary();
  closeAddMemberModal();
  requestAnimationFrame(() => memberScrollList.scrollTo({ top: memberScrollList.scrollHeight, behavior: 'smooth' }));
  recordBudgetIQNotificationEvent({
    type: 'member',
    title: `${name} added as a member`,
    message: 'The shared fund member list was updated.',
    icon: 'person_add'
  });
  triggerToast(`${name} added`, 'person_add', 'text-[#C1FF72]');
}

function toggleMemberPaid(button) {
  if (!requireBudgetIQPermission('payments', 'change payments')) return;
  const row = button ? button.closest('.member-list-row') : null;
  if (!row) return;
  const willBePaid = row.dataset.status !== 'paid';
  if (willBePaid && readBudgetIQContributionForMember(row.dataset.memberId) <= 0) {
    triggerToast('Add this member to the monthly payment plan first', 'warning', 'text-amber-400');
    openMemberContributionModal();
    return;
  }
  setMemberPaymentAppearance(row, willBePaid);
  if (!saveBudgetIQMembers()) {
    setMemberPaymentAppearance(row, !willBePaid);
    updateMemberPaymentSummary();
    return;
  }
  updateMemberPaymentSummary();
  const name = row.querySelector('.member-name')?.innerText || 'Member';
  recordBudgetIQContributionActivity(row.dataset.memberId, name, willBePaid);
  triggerToast(`${name} marked ${willBePaid ? 'Paid' : 'Not Paid'}`, willBePaid ? 'check_circle' : 'cancel', willBePaid ? 'text-[#C1FF72]' : 'text-red-400');
}

function filterMemberRows() {
  const query = (memberSearchInput?.value || '').trim().toLowerCase();
  budgetIQMemberRows.forEach((row) => {
    const name = row.querySelector('.member-name')?.innerText.toLowerCase() || '';
    row.classList.toggle('hidden', !name.includes(query));
  });
}

function prepareMemberRename() {
  if (!editMemberSelect || !editMemberNameInput) return;
  const row = document.querySelector(`.member-list-row[data-member-id="${editMemberSelect.value}"]`);
  editMemberNameInput.value = row?.querySelector('.member-name')?.innerText || '';
  editMemberNameInput.select();
}

function openEditMemberModal() {
  if (!requireBudgetIQPermission('members', 'edit members')) return;
  if (!editMemberModal) return;
  if (!budgetIQMemberRows.length) {
    triggerToast('Add a member first', 'person_add', 'text-amber-400');
    openAddMemberModal();
    return;
  }
  editMemberModal.classList.remove('hidden');
  prepareMemberRename();
  requestAnimationFrame(() => {
    editMemberModal.classList.add('opacity-100');
    const panel = editMemberModal.querySelector('.edit-member-panel');
    panel?.classList.remove('scale-95');
    panel?.classList.add('scale-100');
  });
  setTimeout(() => editMemberNameInput?.focus(), 180);
}

function closeEditMemberModal(event) {
  if (!editMemberModal) return;
  if (event && event.target !== editMemberModal) return;
  editMemberModal.classList.remove('opacity-100');
  const panel = editMemberModal.querySelector('.edit-member-panel');
  panel?.classList.add('scale-95');
  panel?.classList.remove('scale-100');
  setTimeout(() => editMemberModal.classList.add('hidden'), 300);
}

function saveMemberRename() {
  if (!requireBudgetIQPermission('members', 'edit members')) return;
  if (!editMemberSelect || !editMemberNameInput) return;
  const newName = editMemberNameInput.value.trim();
  if (!newName) {
    triggerToast('Please enter a member name', 'error', 'text-red-400');
    return;
  }

  const row = document.querySelector(`.member-list-row[data-member-id="${editMemberSelect.value}"]`);
  const name = row?.querySelector('.member-name');
  if (!row || !name) return;
  const previousName = name.innerText;
  name.innerText = newName;
  const option = editMemberSelect.querySelector(`option[value="${editMemberSelect.value}"]`);
  if (option) option.innerText = newName;
  if (!saveBudgetIQMembers()) {
    name.innerText = previousName;
    if (option) option.innerText = previousName;
    return;
  }
  filterMemberRows();
  closeEditMemberModal();
  recordBudgetIQNotificationEvent({
    type: 'member',
    title: `${previousName} renamed`,
    message: `The member name was changed to ${newName}.`,
    icon: 'manage_accounts'
  });
  triggerToast(`${newName} saved`, 'check_circle', 'text-[#C1FF72]');
}

// Keep the Home summary aligned with the member records saved on the Members page.
const BUDGETIQ_DEFAULT_MEMBER_IDS = [];
const BUDGETIQ_CONTRIBUTION_PER_MEMBER = 0;
const BUDGETIQ_FIXED_EXPENSES = 0;
const BUDGETIQ_MONTHLY_EXPECTED_KEY = 'budgetiq-monthly-expected-amounts';
const BUDGETIQ_MONTHLY_CONTRIBUTION_KEY = 'budgetiq-monthly-contribution-per-member';
const BUDGETIQ_MONTHLY_CONTRIBUTION_GROUPS_KEY = 'budgetiq-monthly-contribution-groups';
const BUDGETIQ_WORKSPACE_USERS_KEY = 'budgetiq-workspace-users';
const BUDGETIQ_PERMISSION_KEYS = ['members', 'payments', 'expenses', 'history', 'reports'];
const BUDGETIQ_ROLE_LABELS = {
  admin: 'Administrator',
  manager: 'Manager',
  member: 'Team member',
  viewer: 'Viewer'
};
const BUDGETIQ_ROLE_PERMISSIONS = {
  admin: { members: true, payments: true, expenses: true, history: true, reports: true },
  manager: { members: true, payments: true, expenses: true, history: true, reports: true },
  member: { members: true, payments: true, expenses: true, history: true, reports: false },
  viewer: { members: false, payments: false, expenses: false, history: true, reports: true }
};
const BUDGETIQ_PROFILE_OVERRIDES_KEY = 'budgetiq-profile-overrides';

function createBudgetIQAdminUser() {
  return {
    id: 'admin',
    name: 'Admin',
    role: 'admin',
    active: true,
    permissions: { ...BUDGETIQ_ROLE_PERMISSIONS.admin }
  };
}

function normalizeBudgetIQWorkspaceUser(user) {
  if (!user || typeof user !== 'object') return null;
  const id = String(user.id || '').trim();
  const name = String(user.name || '').trim();
  if (!id || !name) return null;
  const role = Object.prototype.hasOwnProperty.call(BUDGETIQ_ROLE_LABELS, user.role) ? user.role : 'member';
  const preset = BUDGETIQ_ROLE_PERMISSIONS[role] || BUDGETIQ_ROLE_PERMISSIONS.member;
  const permissions = {};
  BUDGETIQ_PERMISSION_KEYS.forEach((permission) => {
    permissions[permission] = role === 'admin' ? true : user.permissions?.[permission] === true;
    if (!user.permissions || typeof user.permissions !== 'object') permissions[permission] = preset[permission] === true;
  });
  return {
    id,
    name,
    role,
    active: user.active !== false,
    permissions
  };
}

function readBudgetIQWorkspaceUsers() {
  let users = [];
  try {
    const saved = JSON.parse(localStorage.getItem(BUDGETIQ_WORKSPACE_USERS_KEY) || '[]');
    if (Array.isArray(saved)) users = saved.map(normalizeBudgetIQWorkspaceUser).filter(Boolean);
  } catch (error) {
    users = [];
  }

  const adminIndex = users.findIndex((user) => user.id === 'admin');
  if (adminIndex < 0) users.unshift(createBudgetIQAdminUser());
  else users[adminIndex] = { ...createBudgetIQAdminUser(), name: users[adminIndex].name || 'Admin' };
  return users;
}

function saveBudgetIQWorkspaceUsers(users) {
  const normalized = (Array.isArray(users) ? users : []).map(normalizeBudgetIQWorkspaceUser).filter(Boolean);
  const adminIndex = normalized.findIndex((user) => user.id === 'admin');
  if (adminIndex < 0) normalized.unshift(createBudgetIQAdminUser());
  else normalized[adminIndex] = { ...createBudgetIQAdminUser(), name: normalized[adminIndex].name || 'Admin' };
  localStorage.setItem(BUDGETIQ_WORKSPACE_USERS_KEY, JSON.stringify(normalized));
  return normalized;
}

function getBudgetIQWorkspaceUser(userId) {
  return readBudgetIQWorkspaceUsers().find((user) => user.id === String(userId || '')) || null;
}

function getBudgetIQSelectedWorkspaceUser() {
  let selectedUserId = 'admin';
  try {
    selectedUserId = localStorage.getItem('budgetiq-selected-user') || selectedUserId;
  } catch (error) {
    return createBudgetIQAdminUser();
  }
  const user = getBudgetIQWorkspaceUser(selectedUserId);
  if (user?.active) return user;
  try { localStorage.setItem('budgetiq-selected-user', 'admin'); } catch (error) { /* Use Admin in memory. */ }
  return getBudgetIQWorkspaceUser('admin') || createBudgetIQAdminUser();
}

function canBudgetIQ(permission) {
  const user = getBudgetIQSelectedWorkspaceUser();
  if (user.role === 'admin') return true;
  return user.permissions?.[permission] === true;
}

function requireBudgetIQPermission(permission, label = 'use this feature') {
  if (canBudgetIQ(permission)) return true;
  triggerToast(`Admin permission is required to ${label}`, 'lock', 'text-amber-400');
  return false;
}

function getBudgetIQPermissionForPath(pathname) {
  const cleanPath = String(pathname || '').replace(/\/+$/, '');
  if (/\/(plan)(\.html)?$/.test(cleanPath)) return 'members';
  if (/\/(cart)(\.html)?$/.test(cleanPath)) return 'expenses';
  if (/\/(history|notifications)(\.html)?$/.test(cleanPath)) return 'history';
  return null;
}

function applyBudgetIQAccessControl(user = getBudgetIQSelectedWorkspaceUser()) {
  const isAdmin = user.role === 'admin';
  document.querySelectorAll('[data-budgetiq-admin-only]').forEach((element) => {
    element.classList.toggle('hidden', !isAdmin);
  });

  document.querySelectorAll('a[href]').forEach((link) => {
    let permission = null;
    try { permission = getBudgetIQPermissionForPath(new URL(link.href, window.location.href).pathname); } catch (error) { /* Ignore invalid links. */ }
    if (permission) link.classList.toggle('hidden', !canBudgetIQ(permission));
  });

  const currentPath = window.location.pathname;
  const currentPermission = getBudgetIQPermissionForPath(currentPath);
  const onSettingsPage = /\/settings(\.html)?$/.test(currentPath);
  if ((currentPermission && !canBudgetIQ(currentPermission)) || (onSettingsPage && !isAdmin)) {
    const dashboardLink = Array.from(document.querySelectorAll('a[href]')).find((link) => /dashboard(\.html)?$/.test(link.pathname));
    window.location.replace(dashboardLink?.href || '/dashboard');
  }
}

function formatBudgetIQAED(value) {
  const amount = Math.round(Number(value) || 0);
  return `${amount < 0 ? '-' : ''}AED ${Math.abs(amount).toLocaleString('en-US')}`;
}

function getBudgetIQCurrentMonthName() {
  try {
    return localStorage.getItem('budgetiq-selected-month') || 'July 2026';
  } catch (error) {
    return 'July 2026';
  }
}

function readBudgetIQMonthlyExpectedAmounts() {
  try {
    const saved = JSON.parse(localStorage.getItem(BUDGETIQ_MONTHLY_EXPECTED_KEY) || '{}');
    return saved && typeof saved === 'object' && !Array.isArray(saved) ? saved : {};
  } catch (error) {
    return {};
  }
}

function readBudgetIQMonthlyContributionAmounts() {
  try {
    const saved = JSON.parse(localStorage.getItem(BUDGETIQ_MONTHLY_CONTRIBUTION_KEY) || '{}');
    return saved && typeof saved === 'object' && !Array.isArray(saved) ? saved : {};
  } catch (error) {
    return {};
  }
}

function readBudgetIQMonthlyContributionGroups() {
  try {
    const saved = JSON.parse(localStorage.getItem(BUDGETIQ_MONTHLY_CONTRIBUTION_GROUPS_KEY) || '{}');
    return saved && typeof saved === 'object' && !Array.isArray(saved) ? saved : {};
  } catch (error) {
    return {};
  }
}

function readBudgetIQContributionGroupPlan(month = getBudgetIQCurrentMonthName()) {
  const saved = readBudgetIQMonthlyContributionGroups();
  const groups = saved[month];
  if (!Array.isArray(groups) || !groups.length) return null;

  const validGroups = groups.map((group) => ({
    count: Math.round(Number(group?.count) || 0),
    amount: Math.round(Number(group?.amount) || 0)
  })).filter((group) => group.count > 0 && group.amount > 0);
  return validGroups.length === groups.length ? validGroups : null;
}

function readBudgetIQOrderedMemberIds() {
  if (budgetIQMemberRows.length) {
    return budgetIQMemberRows.map((row) => String(row.dataset.memberId || '')).filter(Boolean);
  }

  try {
    const storedIds = JSON.parse(localStorage.getItem(MEMBER_IDS_KEY) || '[]');
    if (Array.isArray(storedIds) && storedIds.length) {
      return [...new Set(storedIds.map(String).filter(Boolean))];
    }
  } catch (error) {
    // Keep the workspace empty when stored member ids are unavailable.
  }
  return [...BUDGETIQ_DEFAULT_MEMBER_IDS];
}

function readBudgetIQContributionForMember(memberId, month = getBudgetIQCurrentMonthName()) {
  const groupPlan = readBudgetIQContributionGroupPlan(month);
  if (groupPlan) {
    const memberIndex = readBudgetIQOrderedMemberIds().indexOf(String(memberId || ''));
    if (memberIndex < 0) return 0;
    let groupEnd = 0;
    for (const group of groupPlan) {
      groupEnd += group.count;
      if (memberIndex < groupEnd) return group.amount;
    }
    return 0;
  }

  const monthlyContributions = readBudgetIQMonthlyContributionAmounts();
  const savedContribution = Number(monthlyContributions[month]);
  if (Number.isFinite(savedContribution) && savedContribution > 0) return savedContribution;
  const memberIds = readBudgetIQOrderedMemberIds();
  if (!memberIds.length) return 0;
  const expectedAmounts = readBudgetIQMonthlyExpectedAmounts();
  const savedExpected = Number(expectedAmounts[month]);
  return Number.isFinite(savedExpected) && savedExpected > 0
    ? savedExpected / memberIds.length
    : BUDGETIQ_CONTRIBUTION_PER_MEMBER;
}

function calculateBudgetIQContributionGroupTotals(groups = readBudgetIQContributionGroupPlan()) {
  const totalMembers = readBudgetIQOrderedMemberIds().length;
  if (!groups) return { assigned: 0, expected: 0, totalMembers };
  let remainingMembers = totalMembers;
  let assigned = 0;
  let expected = 0;
  groups.forEach((group) => {
    const appliedCount = Math.min(group.count, remainingMembers);
    assigned += appliedCount;
    expected += appliedCount * group.amount;
    remainingMembers -= appliedCount;
  });
  return { assigned, expected, totalMembers };
}

function readBudgetIQExpectedAmount(defaultAmount) {
  const groupPlan = readBudgetIQContributionGroupPlan();
  if (groupPlan) return calculateBudgetIQContributionGroupTotals(groupPlan).expected;
  const monthlyContributions = readBudgetIQMonthlyContributionAmounts();
  const contribution = Number(monthlyContributions[getBudgetIQCurrentMonthName()]);
  if (Number.isFinite(contribution) && contribution > 0) {
    return contribution * readBudgetIQMemberSummary().total;
  }
  const saved = readBudgetIQMonthlyExpectedAmounts();
  const amount = Number(saved[getBudgetIQCurrentMonthName()]);
  return Number.isFinite(amount) && amount > 0 ? amount : defaultAmount;
}

function openExpectedAmountModal() {
  if (!requireBudgetIQPermission('members', 'change the fund target')) return;
  const modal = document.getElementById('expectedAmountModal');
  const input = document.getElementById('expectedAmountInput');
  const monthLabel = document.getElementById('expectedAmountMonthLabel');
  const errorLabel = document.getElementById('expectedAmountError');
  if (!modal || !input) return;

  const summary = readBudgetIQMemberSummary();
  const defaultAmount = summary.total * BUDGETIQ_CONTRIBUTION_PER_MEMBER;
  input.value = String(readBudgetIQExpectedAmount(defaultAmount));
  if (monthLabel) monthLabel.textContent = getBudgetIQCurrentMonthName();
  if (errorLabel) errorLabel.classList.add('hidden');
  modal.classList.remove('hidden');
  modal.classList.add('flex');
  document.body.style.overflow = 'hidden';
  setTimeout(() => input.focus(), 80);
}

function closeExpectedAmountModal() {
  const modal = document.getElementById('expectedAmountModal');
  if (modal) {
    modal.classList.add('hidden');
    modal.classList.remove('flex');
  }
  document.body.style.overflow = '';
}

function saveExpectedAmount(event) {
  event.preventDefault();
  if (!requireBudgetIQPermission('members', 'change the fund target')) return;
  const input = document.getElementById('expectedAmountInput');
  const errorLabel = document.getElementById('expectedAmountError');
  const amount = Math.round(Number(input?.value) || 0);

  if (amount <= 0) {
    if (errorLabel) {
      errorLabel.textContent = 'Enter an amount greater than AED 0.';
      errorLabel.classList.remove('hidden');
    }
    input?.focus();
    return;
  }

  try {
    const saved = readBudgetIQMonthlyExpectedAmounts();
    const month = getBudgetIQCurrentMonthName();
    saved[month] = amount;
    localStorage.setItem(BUDGETIQ_MONTHLY_EXPECTED_KEY, JSON.stringify(saved));
    const contributions = readBudgetIQMonthlyContributionAmounts();
    delete contributions[month];
    localStorage.setItem(BUDGETIQ_MONTHLY_CONTRIBUTION_KEY, JSON.stringify(contributions));
    const contributionGroups = readBudgetIQMonthlyContributionGroups();
    delete contributionGroups[month];
    localStorage.setItem(BUDGETIQ_MONTHLY_CONTRIBUTION_GROUPS_KEY, JSON.stringify(contributionGroups));
  } catch (error) {
    if (errorLabel) {
      errorLabel.textContent = 'The expected amount could not be saved on this device.';
      errorLabel.classList.remove('hidden');
    }
    return;
  }

  refreshBudgetIQDashboard();
  closeExpectedAmountModal();
  showNotification(`Expected amount updated to ${formatBudgetIQAED(amount)}.`);
}

function readBudgetIQRecordedExpenseTotal() {
  try {
    const savedExpenses = JSON.parse(localStorage.getItem(BUDGETIQ_EXPENSES_KEY) || '[]');
    if (!Array.isArray(savedExpenses)) return 0;
    const selectedMonth = getBudgetIQCurrentMonthName();
    return savedExpenses.reduce((total, expense) => {
      if (expense?.month !== selectedMonth) return total;
      const amount = Number(expense?.amount);
      return total + (Number.isFinite(amount) && amount > 0 ? amount : 0);
    }, 0);
  } catch (error) {
    return 0;
  }
}

function readBudgetIQMemberSummary() {
  let ids = [...BUDGETIQ_DEFAULT_MEMBER_IDS];
  let payments = {};

  try {
    const storedIds = JSON.parse(localStorage.getItem(MEMBER_IDS_KEY) || '[]');
    const storedPayments = readBudgetIQPaymentsForMonth();
    if (Array.isArray(storedIds) && storedIds.length) {
      ids = [...new Set(storedIds.map(String).filter(Boolean))];
    }
    if (storedPayments && typeof storedPayments === 'object' && !Array.isArray(storedPayments)) {
      payments = storedPayments;
    }
  } catch (error) {
    // Keep the workspace summary empty when saved data is unavailable or invalid.
  }

  const paid = ids.filter((id) => payments[id] === true).length;
  return { total: ids.length, paid, unpaid: ids.length - paid, ids, payments };
}

function readBudgetIQContributionPerMember() {
  const memberIds = readBudgetIQOrderedMemberIds();
  if (!memberIds.length) return 0;
  const groupPlan = readBudgetIQContributionGroupPlan();
  if (groupPlan) return calculateBudgetIQContributionGroupTotals(groupPlan).expected / memberIds.length;
  return readBudgetIQContributionForMember(memberIds[0]);
}

function createMemberContributionGroupRow(count, amount) {
  const container = document.getElementById('memberContributionGroupRows');
  if (!container) return;
  const row = document.createElement('div');
  row.dataset.contributionGroupRow = 'true';
  row.className = 'rounded-2xl border border-white/[0.07] bg-black/20 p-3';
  row.innerHTML = `
    <div class="mb-2 flex items-center justify-between">
      <span class="member-contribution-group-name text-[8px] font-black uppercase tracking-wider text-zinc-500">Group</span>
      <button type="button" onclick="removeMemberContributionGroup(this)" aria-label="Remove payment group"
        class="flex h-6 w-6 items-center justify-center rounded-lg text-zinc-600 transition-all active:scale-90">
        <span class="material-icons text-sm">remove_circle_outline</span>
      </button>
    </div>
    <div class="grid grid-cols-2 gap-2">
      <label class="space-y-1">
        <span class="block text-[8px] font-bold uppercase tracking-wider text-zinc-600">Members</span>
        <input data-contribution-group-count type="number" min="1" step="1" inputmode="numeric" value="${Math.max(1, Math.round(Number(count) || 1))}"
          oninput="updateMemberContributionPlanPreview()"
          class="w-full rounded-xl border border-zinc-800 bg-zinc-900 px-3 py-2.5 text-xs font-extrabold text-white outline-none focus:border-[#C1FF72]/40" />
      </label>
      <label class="space-y-1">
        <span class="block text-[8px] font-bold uppercase tracking-wider text-zinc-600">Amount (AED)</span>
        <input data-contribution-group-amount type="number" min="1" step="1" inputmode="decimal" value="${Math.max(1, Math.round(Number(amount) || 1))}"
          oninput="updateMemberContributionPlanPreview()"
          class="w-full rounded-xl border border-zinc-800 bg-zinc-900 px-3 py-2.5 text-xs font-extrabold text-white outline-none focus:border-[#C1FF72]/40" />
      </label>
    </div>`;
  container.appendChild(row);
  refreshMemberContributionGroupNames();
}

function refreshMemberContributionGroupNames() {
  document.querySelectorAll('[data-contribution-group-row]').forEach((row, index) => {
    const label = row.querySelector('.member-contribution-group-name');
    if (label) label.textContent = `Group ${index + 1}`;
  });
}

function readMemberContributionGroupInputs() {
  return Array.from(document.querySelectorAll('[data-contribution-group-row]')).map((row) => ({
    count: Math.round(Number(row.querySelector('[data-contribution-group-count]')?.value) || 0),
    amount: Math.round(Number(row.querySelector('[data-contribution-group-amount]')?.value) || 0)
  }));
}

function setMemberContributionMode(mode) {
  const modal = document.getElementById('memberContributionModal');
  const everyoneTab = document.getElementById('memberContributionEveryoneTab');
  const groupsTab = document.getElementById('memberContributionGroupsTab');
  const everyonePanel = document.getElementById('memberContributionEveryonePanel');
  const groupsPanel = document.getElementById('memberContributionGroupsPanel');
  const everyoneInput = document.getElementById('memberContributionInput');
  const useGroups = mode === 'groups';
  if (!modal) return;

  modal.dataset.contributionMode = useGroups ? 'groups' : 'everyone';
  everyonePanel?.classList.toggle('hidden', useGroups);
  groupsPanel?.classList.toggle('hidden', !useGroups);
  if (everyoneInput) everyoneInput.required = !useGroups;
  document.querySelectorAll('[data-contribution-group-count], [data-contribution-group-amount]').forEach((input) => {
    input.required = useGroups;
  });

  const activeClasses = ['border-[#C1FF72]/30', 'bg-[#C1FF72]/10', 'text-[#C1FF72]'];
  const inactiveClasses = ['border-white/[0.06]', 'bg-black/20', 'text-zinc-500'];
  [everyoneTab, groupsTab].forEach((tab) => {
    if (!tab) return;
    const active = (tab === groupsTab) === useGroups;
    tab.classList.remove(...(active ? inactiveClasses : activeClasses));
    tab.classList.add(...(active ? activeClasses : inactiveClasses));
    tab.setAttribute('aria-pressed', active ? 'true' : 'false');
  });
  updateMemberContributionPlanPreview();
}

function addMemberContributionGroup() {
  const totalMembers = readBudgetIQOrderedMemberIds().length;
  const assigned = readMemberContributionGroupInputs().reduce((total, group) => total + Math.max(0, group.count), 0);
  createMemberContributionGroupRow(Math.max(1, totalMembers - assigned), Math.round(readBudgetIQContributionPerMember()) || BUDGETIQ_CONTRIBUTION_PER_MEMBER);
  setMemberContributionMode('groups');
}

function removeMemberContributionGroup(button) {
  const rows = document.querySelectorAll('[data-contribution-group-row]');
  if (rows.length <= 1) return;
  button?.closest('[data-contribution-group-row]')?.remove();
  refreshMemberContributionGroupNames();
  updateMemberContributionPlanPreview();
}

function updateMemberContributionPlanPreview() {
  const modal = document.getElementById('memberContributionModal');
  const memberCountLabel = document.getElementById('memberContributionActiveCount');
  const assignedLabel = document.getElementById('memberContributionAssignedSummary');
  const expectedLabel = document.getElementById('memberContributionExpectedSummary');
  const errorLabel = document.getElementById('memberContributionError');
  const totalMembers = readBudgetIQOrderedMemberIds().length;
  const useGroups = modal?.dataset.contributionMode === 'groups';
  let assigned = totalMembers;
  let expected = totalMembers * Math.max(0, Math.round(Number(document.getElementById('memberContributionInput')?.value) || 0));

  if (useGroups) {
    const groups = readMemberContributionGroupInputs();
    assigned = groups.reduce((total, group) => total + Math.max(0, group.count), 0);
    expected = groups.reduce((total, group) => total + (Math.max(0, group.count) * Math.max(0, group.amount)), 0);
  }

  if (memberCountLabel) memberCountLabel.textContent = `${totalMembers} active ${totalMembers === 1 ? 'member' : 'members'}`;
  if (assignedLabel) {
    assignedLabel.textContent = useGroups ? `${assigned} of ${totalMembers} assigned` : `${totalMembers} of ${totalMembers} assigned`;
    assignedLabel.classList.toggle('text-[#C1FF72]', assigned === totalMembers);
    assignedLabel.classList.toggle('text-amber-400', assigned !== totalMembers);
  }
  if (expectedLabel) expectedLabel.textContent = `${formatBudgetIQAED(expected)} expected`;
  errorLabel?.classList.add('hidden');
}

function openMemberContributionModal() {
  if (!requireBudgetIQPermission('payments', 'change the payment plan')) return;
  const modal = document.getElementById('memberContributionModal');
  const input = document.getElementById('memberContributionInput');
  const monthLabel = document.getElementById('memberContributionMonthLabel');
  const errorLabel = document.getElementById('memberContributionError');
  const groupRows = document.getElementById('memberContributionGroupRows');
  if (!modal || !input) return;
  if (!readBudgetIQOrderedMemberIds().length) {
    triggerToast('Add a member before setting payments', 'person_add', 'text-amber-400');
    openAddMemberModal();
    return;
  }

  input.value = String(Math.round(readBudgetIQContributionPerMember()));
  if (monthLabel) monthLabel.textContent = getBudgetIQCurrentMonthName();
  if (errorLabel) errorLabel.classList.add('hidden');
  if (groupRows) groupRows.innerHTML = '';
  const savedGroups = readBudgetIQContributionGroupPlan();
  if (savedGroups) {
    savedGroups.forEach((group) => createMemberContributionGroupRow(group.count, group.amount));
  } else {
    const totalMembers = readBudgetIQOrderedMemberIds().length;
    const firstGroupCount = Math.max(1, Math.ceil(totalMembers / 2));
    const secondGroupCount = Math.max(1, totalMembers - firstGroupCount);
    const defaultAmount = Math.round(readBudgetIQContributionPerMember()) || BUDGETIQ_CONTRIBUTION_PER_MEMBER;
    createMemberContributionGroupRow(firstGroupCount, defaultAmount);
    if (totalMembers > 1) createMemberContributionGroupRow(secondGroupCount, defaultAmount);
  }
  setMemberContributionMode(savedGroups ? 'groups' : 'everyone');
  modal.classList.remove('hidden');
  modal.classList.add('flex');
  document.body.style.overflow = 'hidden';
  setTimeout(() => {
    const targetInput = savedGroups
      ? document.querySelector('[data-contribution-group-count]')
      : input;
    targetInput?.focus();
    targetInput?.select();
  }, 80);
}

function closeMemberContributionModal() {
  const modal = document.getElementById('memberContributionModal');
  if (modal) {
    modal.classList.add('hidden');
    modal.classList.remove('flex');
  }
  document.body.style.overflow = '';
}

function saveMemberContributionAmount(event) {
  event.preventDefault();
  if (!requireBudgetIQPermission('payments', 'change the payment plan')) return;
  const modal = document.getElementById('memberContributionModal');
  const input = document.getElementById('memberContributionInput');
  const errorLabel = document.getElementById('memberContributionError');
  const useGroups = modal?.dataset.contributionMode === 'groups';
  const amount = Math.round(Number(input?.value) || 0);
  const groups = readMemberContributionGroupInputs();
  const totalMembers = readBudgetIQOrderedMemberIds().length;
  const assignedMembers = groups.reduce((total, group) => total + group.count, 0);

  if (!useGroups && amount <= 0) {
    if (errorLabel) {
      errorLabel.textContent = 'Enter an amount greater than AED 0.';
      errorLabel.classList.remove('hidden');
    }
    input?.focus();
    return;
  }

  if (useGroups && (!groups.length || groups.some((group) => group.count <= 0 || group.amount <= 0))) {
    if (errorLabel) {
      errorLabel.textContent = 'Each group needs at least 1 member and an amount above AED 0.';
      errorLabel.classList.remove('hidden');
    }
    return;
  }

  if (useGroups && assignedMembers !== totalMembers) {
    if (errorLabel) {
      const difference = Math.abs(totalMembers - assignedMembers);
      errorLabel.textContent = assignedMembers < totalMembers
        ? `Assign the remaining ${difference} ${difference === 1 ? 'member' : 'members'}.`
        : `Remove ${difference} extra ${difference === 1 ? 'member' : 'members'} from the groups.`;
      errorLabel.classList.remove('hidden');
    }
    return;
  }

  try {
    const month = getBudgetIQCurrentMonthName();
    const contributions = readBudgetIQMonthlyContributionAmounts();
    const contributionGroups = readBudgetIQMonthlyContributionGroups();
    if (useGroups) {
      delete contributions[month];
      contributionGroups[month] = groups;
    } else {
      contributions[month] = amount;
      delete contributionGroups[month];
    }
    localStorage.setItem(BUDGETIQ_MONTHLY_CONTRIBUTION_KEY, JSON.stringify(contributions));
    localStorage.setItem(BUDGETIQ_MONTHLY_CONTRIBUTION_GROUPS_KEY, JSON.stringify(contributionGroups));
    const expectedAmounts = readBudgetIQMonthlyExpectedAmounts();
    delete expectedAmounts[month];
    localStorage.setItem(BUDGETIQ_MONTHLY_EXPECTED_KEY, JSON.stringify(expectedAmounts));
  } catch (error) {
    if (errorLabel) {
      errorLabel.textContent = 'The member payment plan could not be saved on this device.';
      errorLabel.classList.remove('hidden');
    }
    return;
  }

  updateMemberPaymentSummary();
  refreshBudgetIQDashboard();
  closeMemberContributionModal();
  showNotification(useGroups
    ? `${groups.length} payment ${groups.length === 1 ? 'group' : 'groups'} saved for ${totalMembers} members.`
    : `Every member will pay ${formatBudgetIQAED(amount)}.`);
}

function readBudgetIQCollectedTotal() {
  const summary = readBudgetIQMemberSummary();
  return readBudgetIQOrderedMemberIds().reduce((total, memberId) => (
    total + (summary.payments?.[memberId] === true ? readBudgetIQContributionForMember(memberId) : 0)
  ), 0);
}

function refreshBudgetIQDashboard() {
  const totalLabel = document.getElementById('fundMemberTotal');
  if (!totalLabel) return;

  const summary = readBudgetIQMemberSummary();
  const defaultExpected = summary.total * BUDGETIQ_CONTRIBUTION_PER_MEMBER;
  const expected = readBudgetIQExpectedAmount(defaultExpected);
  const collected = readBudgetIQCollectedTotal();
  const amountLeft = expected - collected;
  const expenses = BUDGETIQ_FIXED_EXPENSES + readBudgetIQRecordedExpenseTotal();
  const available = collected - expenses;
  const percent = expected ? Math.round((collected / expected) * 100) : 0;

  const values = {
    fundMemberTotal: String(summary.total),
    fundPaidCount: String(summary.paid),
    fundUnpaidCount: String(summary.unpaid),
    fundExpected: formatBudgetIQAED(expected),
    fundCollected: formatBudgetIQAED(collected),
    fundExpenses: formatBudgetIQAED(expenses),
    fundCurrentBalance: formatBudgetIQAED(available),
    fundAmountLeft: formatBudgetIQAED(amountLeft),
    fundTotalTarget: formatBudgetIQAED(expected),
    fundCollectionPercent: `${percent}%`
  };

  Object.entries(values).forEach(([id, value]) => {
    const element = document.getElementById(id);
    if (element) element.textContent = value;
  });

  ['fundCollectionProgress', 'fundStatusProgress'].forEach((id) => {
    const element = document.getElementById(id);
    if (element) element.style.width = `${percent}%`;
  });
}

function applyBudgetIQSelectedUser() {
  const homeUserName = document.getElementById('homeUserName');
  const workspaceUser = getBudgetIQSelectedWorkspaceUser();
  const selectedUser = workspaceUser.id;
  let profileOverrides = {};
  try {
    profileOverrides = JSON.parse(localStorage.getItem(BUDGETIQ_PROFILE_OVERRIDES_KEY) || '{}');
  } catch (error) {
    // Keep the Admin greeting when storage is unavailable.
  }
  const savedProfile = profileOverrides && typeof profileOverrides === 'object'
    ? profileOverrides[selectedUser]
    : null;
  const userLabel = savedProfile?.name || workspaceUser.name || 'Admin';
  const roleLabel = BUDGETIQ_ROLE_LABELS[workspaceUser.role] || BUDGETIQ_ROLE_LABELS.member;
  const userSubtitle = savedProfile?.subtitle || `BudgetIQ Workspace • ${roleLabel} access`;
  const generatedInitials = userLabel.split(/\s+/).filter(Boolean).map((part) => part[0]).join('').slice(0, 2).toUpperCase();
  const userInitial = generatedInitials || 'A';
  if (homeUserName) homeUserName.textContent = `${userLabel}!`;

  const sidebarAvatar = document.getElementById('budgetIQSidebarAvatar');
  const sidebarUser = document.getElementById('budgetIQSidebarUser');
  const sidebarFooterUser = document.getElementById('budgetIQSidebarFooterUser');
  if (sidebarAvatar) sidebarAvatar.textContent = userInitial;
  if (sidebarUser) sidebarUser.textContent = `${userLabel} ⚡`;
  if (sidebarFooterUser) sidebarFooterUser.textContent = userLabel;

  const profileHeaderAvatar = document.getElementById('profileHeaderAvatar');
  const profileAvatarBadge = document.getElementById('avatarBadge');
  const profileUserName = document.getElementById('profileUserNameText');
  const profileUserRole = document.getElementById('userRole');
  const profileFundMonth = document.getElementById('profileFundMonth');
  const profileFundSummary = document.getElementById('profileFundSummary');
  const profileNameInput = document.getElementById('inputName');
  const profileRoleInput = document.getElementById('inputRole');

  if (profileHeaderAvatar) profileHeaderAvatar.textContent = userInitial;
  if (profileAvatarBadge) profileAvatarBadge.textContent = userInitial;
  if (profileUserName) profileUserName.textContent = userLabel;
  if (profileUserRole) profileUserRole.textContent = userSubtitle;
  if (profileNameInput) profileNameInput.value = userLabel;
  if (profileRoleInput) profileRoleInput.value = userSubtitle;

  if (profileFundMonth) {
    let selectedMonth = 'July 2026';
    try {
      selectedMonth = localStorage.getItem('budgetiq-selected-month') || selectedMonth;
    } catch (error) {
      // Keep the default month when saved month data is unavailable.
    }
    profileFundMonth.textContent = `${selectedMonth} Shared Fund`;
  }
  if (profileFundSummary) {
    const summary = readBudgetIQMemberSummary();
    const access = workspaceUser.role === 'admin' ? 'Admin access' : `${roleLabel} access`;
    profileFundSummary.textContent = `${summary.total} members • ${access}`;
  }

  applyBudgetIQAccessControl(workspaceUser);
}

refreshBudgetIQDashboard();
applyBudgetIQSelectedUser();
loadBudgetIQMembers();

window.addEventListener('storage', (event) => {
  if ([MEMBER_IDS_KEY, MEMBER_PAYMENTS_KEY, MEMBER_MONTHLY_PAYMENTS_KEY, BUDGETIQ_EXPENSES_KEY, BUDGETIQ_MONTHLY_EXPECTED_KEY, BUDGETIQ_MONTHLY_CONTRIBUTION_KEY, BUDGETIQ_MONTHLY_CONTRIBUTION_GROUPS_KEY, 'budgetiq-selected-month'].includes(event.key)) refreshBudgetIQDashboard();
  if (['budgetiq-selected-user', 'budgetiq-selected-month', BUDGETIQ_WORKSPACE_USERS_KEY].includes(event.key)) applyBudgetIQSelectedUser();
  if ([
    MEMBER_IDS_KEY,
    MEMBER_NAMES_KEY,
    MEMBER_PAYMENTS_KEY,
    MEMBER_MONTHLY_PAYMENTS_KEY,
    BUDGETIQ_EXPENSES_KEY,
    BUDGETIQ_CONTRIBUTION_ACTIVITY_KEY,
    'budgetiq-selected-user',
    'budgetiq-selected-month'
  ].includes(event.key)) renderBudgetIQProfileActivity();
});

// =======================================================
// 12C. BUDGETIQ IPHONE BACKUP & RESTORE
// =======================================================
const BUDGETIQ_BACKUP_APP_ID = 'budgetiq-iphone';
const BUDGETIQ_LAST_BACKUP_KEY = 'budgetiq-last-backup-at';

function collectBudgetIQLocalStorage() {
  const records = {};
  for (let index = 0; index < localStorage.length; index += 1) {
    const key = localStorage.key(index);
    if (key?.startsWith('budgetiq-')) records[key] = localStorage.getItem(key);
  }
  return records;
}

function formatBudgetIQBackupTimestamp(value) {
  const date = new Date(value || '');
  if (Number.isNaN(date.getTime())) return 'No backup exported yet';
  return `Last backup: ${date.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })} at ${date.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit' })}`;
}

function refreshBudgetIQBackupStatus() {
  const label = document.getElementById('backupStatusLabel');
  if (!label) return;
  try {
    label.textContent = formatBudgetIQBackupTimestamp(localStorage.getItem(BUDGETIQ_LAST_BACKUP_KEY));
  } catch (error) {
    label.textContent = 'Backup status unavailable';
  }
}

function downloadBudgetIQBackup(reason = 'manual') {
  let createdAt = new Date().toISOString();
  try {
    if (reason === 'manual') localStorage.setItem(BUDGETIQ_LAST_BACKUP_KEY, createdAt);
    const backup = {
      app: BUDGETIQ_BACKUP_APP_ID,
      formatVersion: 2,
      createdAt,
      reason,
      data: collectBudgetIQLocalStorage()
    };
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    const safeDate = createdAt.replace(/[:.]/g, '-');
    link.href = url;
    link.download = `budgetiq-iphone-backup-${safeDate}.json`;
    document.body.appendChild(link);
    link.click();
    link.remove();
    setTimeout(() => URL.revokeObjectURL(url), 1000);
    refreshBudgetIQBackupStatus();
    if (reason === 'manual') triggerToast('Complete iPhone backup created', 'cloud_done', 'text-[#C1FF72]');
    return true;
  } catch (error) {
    triggerToast('Backup could not be created', 'error', 'text-red-400');
    return false;
  }
}

function openBudgetIQRestorePicker() {
  document.getElementById('budgetIQRestoreInput')?.click();
}

async function restoreBudgetIQBackup(event) {
  const input = event?.target;
  const file = input?.files?.[0];
  if (!file) return;

  try {
    if (file.size > 30 * 1024 * 1024) throw new Error('This backup file is too large.');
    const backup = JSON.parse(await file.text());
    if (backup?.app !== BUDGETIQ_BACKUP_APP_ID || !backup.data || typeof backup.data !== 'object' || Array.isArray(backup.data)) {
      throw new Error('This is not a valid BudgetIQ iPhone backup.');
    }

    const importedEntries = Object.entries(backup.data).filter(([key, value]) => (
      key.startsWith('budgetiq-') && typeof value === 'string'
    ));
    if (!importedEntries.length) throw new Error('This backup does not contain BudgetIQ data.');
    if (!window.confirm('Restore this backup? Current BudgetIQ data on this iPhone will be replaced.')) return;

    const currentData = collectBudgetIQLocalStorage();
    if (!downloadBudgetIQBackup('before-restore')) {
      throw new Error('The safety backup could not be created, so the restore was cancelled.');
    }

    try {
      Object.keys(currentData).forEach((key) => localStorage.removeItem(key));
      importedEntries.forEach(([key, value]) => localStorage.setItem(key, value));
      localStorage.setItem('budgetiq-storage-schema-version', '3');
    } catch (storageError) {
      Object.keys(collectBudgetIQLocalStorage()).forEach((key) => localStorage.removeItem(key));
      Object.entries(currentData).forEach(([key, value]) => localStorage.setItem(key, value));
      throw new Error('The restore did not fit in iPhone storage. Your previous data was put back.');
    }

    triggerToast('Backup restored successfully', 'restore', 'text-[#C1FF72]');
    setTimeout(() => window.location.reload(), 900);
  } catch (error) {
    alert(error.message || 'The backup could not be restored.');
  } finally {
    if (input) input.value = '';
  }
}

refreshBudgetIQBackupStatus();


