function exportPurchaseReportPDF() {
  if (requireBudgetIQPermission('reports', 'export reports')) exportBudgetIQMonthlyHistoryPDF();
}

function exportPurchaseReportExcel() {
  if (requireBudgetIQPermission('reports', 'export reports')) exportBudgetIQMonthlyHistoryExcel();
}

function getBudgetIQActivityStatusClass(status) {
  if (status === 'Reversed') return 'bg-red-500/10 text-red-500';
  if (status === 'Paid') return 'bg-emerald-500/10 text-emerald-400';
  return 'bg-[#C1FF72]/10 text-[#C1FF72]';
}

function renderBudgetIQProfileActivity() {
  const list = document.getElementById('profileActivityList');
  if (!list) return;
  const activities = readBudgetIQProfileActivities();
  refreshBudgetIQHistoryPdfCard();
  budgetIQProfileActivitiesById = new Map(activities.map((activity) => [activity.id, activity]));
  const visibleActivities = activities
    .filter((activity) => budgetIQProfileActivityFilter === 'all' || activity.type === budgetIQProfileActivityFilter);

  if (!visibleActivities.length) {
    list.innerHTML = `
      <div class="rounded-2xl border border-dashed border-zinc-800 bg-zinc-900/30 px-5 py-8 text-center">
        <span class="material-icons text-2xl text-zinc-700">history</span>
        <p class="mt-2 text-[10px] font-bold uppercase tracking-wider text-zinc-500">No activity recorded yet</p>
        <p class="mt-1 text-[9px] font-semibold text-zinc-600">Save an expense or update a member payment.</p>
      </div>`;
    return;
  }

  const selectedMonth = getBudgetIQProfileSelectedMonth();
  list.innerHTML = visibleActivities.map((activity) => `
    <div data-activity-id="${escapeBudgetIQHtml(activity.id)}" onclick="openBudgetIQProfileActivity(this.dataset.activityId)"
      class="order-item bg-zinc-900/60 hover:bg-zinc-900/80 border border-zinc-800 rounded-2xl p-4 flex justify-between items-center transition-all cursor-pointer">
      <div class="flex min-w-0 items-center gap-3">
        <div class="w-10 h-10 shrink-0 rounded-xl border flex items-center justify-center ${activity.iconClass}">
          <span class="material-icons text-sm">${activity.icon}</span>
        </div>
        <div class="min-w-0">
          <h4 class="truncate text-xs font-bold text-white tracking-wide">${escapeBudgetIQHtml(activity.title)}</h4>
          <p class="mt-0.5 truncate text-[9px] font-semibold text-gray-500">${escapeBudgetIQHtml(formatBudgetIQProfileDate(activity.createdAt, selectedMonth))} • ${escapeBudgetIQHtml(activity.meta)}</p>
        </div>
      </div>
      <div class="ml-3 shrink-0 text-right space-y-1">
        <span class="text-xs font-black ${activity.status === 'Reversed' ? 'text-red-400' : 'text-[#C1FF72]'} block">${formatBudgetIQProfileAmount(activity.amount)}</span>
        <span class="${getBudgetIQActivityStatusClass(activity.status)} text-[8px] font-black px-2 py-0.5 rounded-full uppercase tracking-wider">${escapeBudgetIQHtml(activity.status)}</span>
      </div>
    </div>`).join('');
}

function scrollBudgetIQActivity(direction) {
  const list = document.getElementById('profileActivityList');
  if (!list) return;
  const distance = Math.max(180, Math.round(list.clientHeight * 0.72));
  list.scrollBy({
    top: direction < 0 ? -distance : distance,
    behavior: 'smooth'
  });
}

function filterOrders(type, element) {
  budgetIQProfileActivityFilter = ['contribution', 'expense'].includes(type) ? type : 'all';
  const buttons = document.querySelectorAll('.filter-btn');
  buttons.forEach(btn => {
    btn.className = "filter-btn text-gray-400 text-[9px] font-extrabold px-3.5 py-1.5 rounded-lg uppercase hover:text-white transition-all";
  });
  if (element) {
    element.className = "filter-btn bg-[#C1FF72] text-black text-[9px] font-black px-3.5 py-1.5 rounded-lg uppercase transition-all shadow-md";
  }
  renderBudgetIQProfileActivity();
  const list = document.getElementById('profileActivityList');
  if (list) list.scrollTop = 0;
}

function openEditProfileSheet() {
  if (editProfileSheet) {
    editProfileSheet.classList.remove('hidden');
    setTimeout(() => {
      editProfileSheet.classList.add('opacity-100');
      const container = editProfileSheet.querySelector('.translate-y-full');
      if (container) container.classList.remove('translate-y-full');
    }, 10);
  }
}

function closeEditProfileSheet() {
  if (!editProfileSheet) return;
  const container = editProfileSheet.querySelector('.transition-transform');
  if (container) container.classList.add('translate-y-full');
  editProfileSheet.classList.remove('opacity-100');
  setTimeout(() => {
    editProfileSheet.classList.add('hidden');
  }, 300);
}

function saveProfileChanges() {
  const inputName = document.getElementById('inputName');
  const inputRole = document.getElementById('inputRole');
  if (!inputName || !inputRole) return;

  const newName = inputName.value.trim();
  const newSubtitle = inputRole.value.trim();

  if (newName && newSubtitle) {
    try {
      const selectedUser = localStorage.getItem('budgetiq-selected-user') || 'admin';
      const savedOverrides = JSON.parse(localStorage.getItem(BUDGETIQ_PROFILE_OVERRIDES_KEY) || '{}');
      const profileOverrides = savedOverrides && typeof savedOverrides === 'object' && !Array.isArray(savedOverrides)
        ? savedOverrides
        : {};
      profileOverrides[selectedUser] = { name: newName, subtitle: newSubtitle };
      localStorage.setItem(BUDGETIQ_PROFILE_OVERRIDES_KEY, JSON.stringify(profileOverrides));
      const users = readBudgetIQWorkspaceUsers();
      const userIndex = users.findIndex((user) => user.id === selectedUser);
      if (userIndex >= 0) {
        users[userIndex] = { ...users[userIndex], name: newName };
        saveBudgetIQWorkspaceUsers(users);
      }
    } catch (error) {
      alert('The profile could not be saved on this device. Please try again.');
      return;
    }

    applyBudgetIQSelectedUser();
    closeEditProfileSheet();
    showToast("Profile updated successfully! ⚡", "check_circle", "text-[#C1FF72]");
  } else {
    alert("Please fill out all fields.");
  }
}

function openBudgetIQProfileActivity(activityId) {
  const activity = budgetIQProfileActivitiesById.get(String(activityId || ''));
  if (!activity) return;
  openOrderDetailModal(
    activity.title,
    activity.type === 'contribution' ? 'Contribution' : 'Expense',
    formatBudgetIQProfileAmount(activity.amount),
    formatBudgetIQProfileDate(activity.createdAt, activity.month),
    activity.status,
    {
      icon: activity.icon,
      personLabel: activity.personLabel,
      person: activity.person,
      detailLabel: activity.detailLabel,
      detail: activity.detail,
      reference: activity.reference
    }
  );
}

function openOrderDetailModal(title, type, price, date, status, details = {}) {
  if (!orderDetailModal) return;
  const modalIcon = document.getElementById('modalActivityIcon');
  const modalTitle = document.getElementById('modalTitle');
  const modalMeta = document.getElementById('modalMeta');
  const modalPrice = document.getElementById('modalPrice');
  const modalPersonLabel = document.getElementById('modalPersonLabel');
  const modalPerson = document.getElementById('modalPerson');
  const modalDetailLabel = document.getElementById('modalDetailLabel');
  const modalDetail = document.getElementById('modalDetail');
  const modalReference = document.getElementById('modalReference');
  const statusLabel = document.getElementById('modalStatus');

  if (modalIcon) modalIcon.innerText = details.icon || 'receipt_long';
  if (modalTitle) modalTitle.innerText = title;
  if (modalMeta) modalMeta.innerText = `${date} • ${type}`;
  if (modalPrice) modalPrice.innerText = price;
  if (modalPersonLabel) modalPersonLabel.innerText = details.personLabel || 'Purchased By';
  if (modalPerson) modalPerson.innerText = details.person || 'Admin';
  if (modalDetailLabel) modalDetailLabel.innerText = details.detailLabel || 'Category';
  if (modalDetail) modalDetail.innerText = details.detail || 'Other';
  if (modalReference) modalReference.innerText = details.reference || 'BIQ-0000';

  if (statusLabel) {
    statusLabel.innerText = status;
    if (['Paid', 'Recorded', 'Approved', 'Active'].includes(status)) {
      statusLabel.className = "text-[#C1FF72] font-black uppercase tracking-wider";
    } else {
      statusLabel.className = "text-red-500 font-black uppercase tracking-wider";
    }
  }

  orderDetailModal.classList.remove('hidden');
  setTimeout(() => {
    orderDetailModal.classList.add('opacity-100');
    const container = orderDetailModal.querySelector('.scale-95');
    if (container) container.classList.remove('scale-95');
  }, 10);
}

function closeOrderDetailModal() {
  if (!orderDetailModal) return;
  const container = orderDetailModal.querySelector('.transition-transform');
  if (container) container.classList.add('scale-95');
  orderDetailModal.classList.remove('opacity-100');
  setTimeout(() => {
    orderDetailModal.classList.add('hidden');
  }, 300);
}

if (editProfileSheet) {
  editProfileSheet.addEventListener('click', (e) => {
    if (e.target === editProfileSheet) closeEditProfileSheet();
  });
}

renderBudgetIQProfileActivity();


