// 16. SPLASH USER PICKER & ADMIN-MANAGED LOCAL USERS
// =======================================================
const SPLASH_PASSWORDS_KEY = 'budgetiq-user-passwords';
let splashActiveUserValue = null;
let splashUnlockedUserValue = null;
let splashPendingUserValue = null;
let splashPendingNavigation = null;
let splashPasswordIsSetup = false;

function populateBudgetIQSplashUsers() {
  const selector = document.getElementById('splashUserSelect');
  if (!selector) return;
  const previousValue = selector.value;
  selector.innerHTML = '';
  readBudgetIQWorkspaceUsers().filter((user) => user.active).forEach((user) => {
    const option = document.createElement('option');
    const initials = user.name.split(/\s+/).filter(Boolean).map((part) => part[0]).join('').slice(0, 2).toUpperCase() || 'U';
    option.value = user.id;
    option.dataset.initial = initials;
    option.textContent = user.name;
    selector.appendChild(option);
  });
  if (Array.from(selector.options).some((option) => option.value === previousValue)) selector.value = previousValue;
}

function getSplashUserOption(userValue) {
  const selector = document.getElementById('splashUserSelect');
  if (!selector) return null;
  return Array.from(selector.options).find((option) => option.value === userValue) || null;
}

function applySplashUser(userValue) {
  const selectedOption = getSplashUserOption(userValue);
  if (!selectedOption) return;

  const nameLabel = document.getElementById('currentUserName');
  const avatarLabel = document.getElementById('currentUserAvatar');

  if (nameLabel) nameLabel.textContent = selectedOption.text;
  if (avatarLabel) avatarLabel.textContent = selectedOption.dataset.initial || 'U';
}

function getSplashPasswordRecords() {
  try {
    const records = JSON.parse(localStorage.getItem(SPLASH_PASSWORDS_KEY) || '{}');
    return records && typeof records === 'object' && !Array.isArray(records) ? records : {};
  } catch (error) {
    return {};
  }
}

function isValidSplashPasswordRecord(record) {
  return Boolean(record && typeof record.salt === 'string' && typeof record.hash === 'string');
}

function saveSplashPasswordRecords(records) {
  localStorage.setItem(SPLASH_PASSWORDS_KEY, JSON.stringify(records));
}

function bytesToBase64(bytes) {
  let binary = '';
  bytes.forEach((byte) => { binary += String.fromCharCode(byte); });
  return btoa(binary);
}

function base64ToBytes(value) {
  const binary = atob(value);
  return Uint8Array.from(binary, (character) => character.charCodeAt(0));
}

